class PriorityQueue {
    constructor() { this.heap = []; }
    push(item, priority) {
        this.heap.push({item, priority}); let i = this.heap.length - 1;
        while (i > 0) {
            const p = Math.floor((i - 1) / 2);
            if (this.heap[i].priority >= this.heap[p].priority) break;
            [this.heap[i], this.heap[p]] = [this.heap[p], this.heap[i]]; i = p;
        }
    }
    pop() {
        if (!this.heap.length) return null; const top = this.heap[0];
        this.heap[0] = this.heap.pop(); let i = 0;
        while (true) {
            let smallest = i, l = 2*i+1, r = 2*i+2;
            if (l < this.heap.length && this.heap[l].priority < this.heap[smallest].priority) smallest = l;
            if (r < this.heap.length && this.heap[r].priority < this.heap[smallest].priority) smallest = r;
            if (smallest === i) break;
            [this.heap[i], this.heap[smallest]] = [this.heap[smallest], this.heap[i]]; i = smallest;
        }
        return top.item;
    }
    isEmpty() { return this.heap.length === 0; }
}

