        idx = self._hash(key)
        for i, (k, v) in enumerate(self.buckets[idx]):
            if k == key: self.buckets[idx][i] = (key, value); return
        self.buckets[idx].append((key, value)); self.size += 1
    def get(self, key):
        idx = self._hash(key)
        for k, v in self.buckets[idx]:
            if k == key: return v
        return None
    def remove(self, key):
