        for (let i = 0; i < bucket.length; i++) { if (bucket[i][0] === key) { bucket[i][1] = value; return; } }
        bucket.push([key, value]); this.size++;
    }
    get(key) { const idx = this._hash(key); for (const [k, v] of this.buckets[idx]) if (k === key) return v; return null; }
    remove(key) { const idx = this._hash(key); const bucket = this.buckets[idx]; for (let i = 0; i < bucket.length; i++) { if (bucket[i][0] === key) { bucket.splice(i, 1); this.size--; return true; } } return false; }
}

type HashMap struct { buckets [][]struct{ key, value interface{} }; size, capacity int }
func NewHashMap(capacity int) *HashMap {
    b := make([][]struct{ key, value interface{} }, capacity)
    for i := range b { b[i] = make([]struct{ key, value interface{} }, 0) }
    return &HashMap{buckets: b, capacity: capacity}
}
func (m *HashMap) hash(key interface{}) int {
    h := 0; s := fmt.Sprint(key)
    for _, c := range s { h = int(c) + (h << 6) + (h << 16) - h }
    if h < 0 { h = -h }; return h % m.capacity
}
func (m *HashMap) Put(key, value interface{}) {
    idx := m.hash(key)
    for i, e := range m.buckets[idx] { if e.key == key { m.buckets[idx][i].value = value; return } }
    m.buckets[idx] = append(m.buckets[idx], struct{ key, value interface{} }{key, value}); m.size++
}
func (m *HashMap) Get(key interface{}) interface{} {
    idx := m.hash(key)
    for _, e := range m.buckets[idx] { if e.key == key { return e.value } }
    return nil
}
func (m *HashMap) Remove(key interface{}) bool {
    idx := m.hash(key)
    for i, e := range m.buckets[idx] {
        if e.key == key { m.buckets[idx] = append(m.buckets[idx][:i], m.buckets[idx][i+1:]...); m.size--; return true }
    }
    return false
}

