class BloomFilter:
    def __init__(self, size, num_hashes):
        self.size = size; self.num_hashes = num_hashes; self.bits = [False] * size
    def _hashes(self, item): return [int(hashlib.md5(f'{item}{i}'.encode()).hexdigest(), 16) % self.size for i in range(self.num_hashes)]
    def add(self, item):
        for h in self._hashes(item): self.bits[h] = True
    def might_contain(self, item): return all(self.bits[h] for h in self._hashes(item))

class BloomFilter {
    constructor(size, numHashes) { this.size = size; this.numHashes = numHashes; this.bits = new Array(size).fill(false); }
    _hash(item, seed) { let h = 0; const s = String(item) + seed; for (let i = 0; i < s.length; i++) h = ((h << 5) - h) + s.charCodeAt(i) | 0; return Math.abs(h) % this.size; }
    add(item) { for (let i = 0; i < this.numHashes; i++) this.bits[this._hash(item, i)] = true; }
    mightContain(item) { for (let i = 0; i < this.numHashes; i++) if (!this.bits[this._hash(item, i)]) return false; return true; }
}

