function reservoirSample(stream, k) {
    const reservoir = [];
    for (let i = 0; i < stream.length; i++) {
        if (i < k) reservoir.push(stream[i]);
        else { const j = Math.floor(Math.random() * (i + 1)); if (j < k) reservoir[j] = stream[i]; }
    }
