class RateLimiter:
    def __init__(self, max_requests, window_seconds):
        self.max_requests = max_requests; self.window = window_seconds; self.requests = []
    def allow(self):
        now = time.time()
        self.requests = [t for t in self.requests if now - t < self.window]
        if len(self.requests) < self.max_requests: self.requests.append(now); return True
        return False

class RateLimiter {
    constructor(maxRequests, windowMs) { this.maxRequests = maxRequests; this.window = windowMs; this.requests = []; }
    allow() {
        const now = Date.now(); this.requests = this.requests.filter(t => now - t < this.window);
        if (this.requests.length < this.maxRequests) { this.requests.push(now); return true; }
        return false;
    }
}

type RateLimiter struct { maxRequests int; window time.Duration; requests []time.Time; mu sync.Mutex }
func NewRateLimiter(maxRequests int, window time.Duration) *RateLimiter { return &RateLimiter{maxRequests: maxRequests, window: window} }
func (rl *RateLimiter) Allow() bool {
    rl.mu.Lock(); defer rl.mu.Unlock()
    now := time.Now(); cutoff := now.Add(-rl.window)
    filtered := make([]time.Time, 0)
    for _, t := range rl.requests { if t.After(cutoff) { filtered = append(filtered, t) } }
    rl.requests = filtered
    if len(rl.requests) < rl.maxRequests { rl.requests = append(rl.requests, now); return true }
    return false
}

import time
class CircuitBreaker:
    def __init__(self, failure_threshold, recovery_timeout):
        self.failure_threshold = failure_threshold; self.recovery_timeout = recovery_timeout
        self.failure_count = 0; self.last_failure_time = 0; self.state = 'CLOSED'
    def call(self, func, *args, **kwargs):
        if self.state == 'OPEN':
            if time.time() - self.last_failure_time > self.recovery_timeout: self.state = 'HALF_OPEN'
            else: raise Exception('Circuit breaker is OPEN')
        try:
            result = func(*args, **kwargs)
            self.failure_count = 0; self.state = 'CLOSED'; return result
        except Exception as e:
            self.failure_count += 1; self.last_failure_time = time.time()
            if self.failure_count >= self.failure_threshold: self.state = 'OPEN'
            raise e

class CircuitBreaker {
    constructor(failureThreshold, recoveryTimeoutMs) {
        this.failureThreshold = failureThreshold; this.recoveryTimeout = recoveryTimeoutMs;
        this.failureCount = 0; this.lastFailureTime = 0; this.state = 'CLOSED';
    }
    async call(fn, ...args) {
        if (this.state === 'OPEN') {
            if (Date.now() - this.lastFailureTime > this.recoveryTimeout) this.state = 'HALF_OPEN';
            else throw new Error('Circuit breaker is OPEN');
        }
        try {
            const result = await fn(...args);
            this.failureCount = 0; this.state = 'CLOSED'; return result;
        } catch (err) {
            this.failureCount++; this.lastFailureTime = Date.now();
            if (this.failureCount >= this.failureThreshold) this.state = 'OPEN';
            throw err;
        }
    }
}

type CircuitBreaker struct { failureThreshold int; recoveryTimeout time.Duration; failureCount int; lastFailureTime time.Time; state string; mu sync.Mutex }
func NewCircuitBreaker(threshold int, timeout time.Duration) *CircuitBreaker {
    return &CircuitBreaker{failureThreshold: threshold, recoveryTimeout: timeout, state: "CLOSED"}
}
func (cb *CircuitBreaker) Call(fn func() (interface{}, error)) (interface{}, error) {
    cb.mu.Lock()
    if cb.state == "OPEN" {
        if time.Since(cb.lastFailureTime) > cb.recoveryTimeout { cb.state = "HALF_OPEN" } else { cb.mu.Unlock(); return nil, fmt.Errorf("circuit breaker is OPEN") }
    }
    cb.mu.Unlock(); result, err := fn()
    cb.mu.Lock(); defer cb.mu.Unlock()
    if err != nil { cb.failureCount++; cb.lastFailureTime = time.Now(); if cb.failureCount >= cb.failureThreshold { cb.state = "OPEN" }; return nil, err }
    cb.failureCount = 0; cb.state = "CLOSED"; return result, nil
}

import time, random
def retry(func, max_retries=3, base_delay=1, backoff_factor=2):
    for attempt in range(max_retries):
        try: return func()
        except Exception as e:
            if attempt == max_retries - 1: raise e
            delay = base_delay * (backoff_factor ** attempt) + random.uniform(0, 0.5)
            time.sleep(delay)

async function retry(fn, maxRetries = 3, baseDelay = 1000, backoffFactor = 2) {
    for (let attempt = 0; attempt < maxRetries; attempt++) {
        try { return await fn(); }
        catch (err) {
            if (attempt === maxRetries - 1) throw err;
            const delay = baseDelay * Math.pow(backoffFactor, attempt) + Math.random() * 500;
            await new Promise(r => setTimeout(r, delay));
        }
    }
}

public static <T> T retry(Supplier<T> func, int maxRetries, long baseDelayMs, double backoffFactor) {
    for (int attempt = 0; attempt < maxRetries; attempt++) {
        try { return func.get(); }
        catch (Exception e) {
            if (attempt == maxRetries - 1) throw e;
            long delay = (long) (baseDelayMs * Math.pow(backoffFactor, attempt) + Math.random() * 500);
            try { Thread.sleep(delay); } catch (InterruptedException ie) { Thread.currentThread().interrupt(); throw e; }
        }
    }
    return null;
}

