import hashlib, bisect
class ConsistentHash:
    def __init__(self, nodes=None, replicas=3):
        self.replicas = replicas; self.ring = {}; self.sorted_keys = []
        if nodes:
            for node in nodes: self.add_node(node)
    def _hash(self, key): return int(hashlib.md5(key.encode()).hexdigest(), 16)
    def add_node(self, node):
        for i in range(self.replicas):
            h = self._hash(f'{node}:{i}')
            self.ring[h] = node; self.sorted_keys.append(h)
        self.sorted_keys.sort()
    def remove_node(self, node):
        for i in range(self.replicas):
            h = self._hash(f'{node}:{i}')
            del self.ring[h]; self.sorted_keys.remove(h)
    def get_node(self, key):
        if not self.ring: return None
        h = self._hash(key)
        idx = bisect.bisect_right(self.sorted_keys, h) % len(self.sorted_keys)
        return self.ring[self.sorted_keys[idx]]

class ConsistentHash {
    constructor(nodes = [], replicas = 3) { this.replicas = replicas; this.ring = new Map(); this.sortedKeys = []; for (const node of nodes) this.addNode(node); }
    _hash(key) { let h = 0; for (let i = 0; i < key.length; i++) h = ((h << 5) - h) + key.charCodeAt(i) | 0; return h >>> 0; }
    addNode(node) {
        for (let i = 0; i < this.replicas; i++) { const h = this._hash(node + ':' + i); this.ring.set(h, node); this.sortedKeys.push(h); }
        this.sortedKeys.sort((a, b) => a - b);
    }
    removeNode(node) {
        for (let i = 0; i < this.replicas; i++) { const h = this._hash(node + ':' + i); this.ring.delete(h); this.sortedKeys.splice(this.sortedKeys.indexOf(h), 1); }
    }
    getNode(key) { if (!this.ring.size) return null; const h = this._hash(key); let idx = this.sortedKeys.findIndex(k => k >= h); if (idx === -1) idx = 0; return this.ring.get(this.sortedKeys[idx]); }
}

type ConsistentHash struct { replicas int; ring map[int]string; sortedKeys []int; mu sync.RWMutex }
func NewConsistentHash(replicas int) *ConsistentHash { return &ConsistentHash{replicas: replicas, ring: make(map[int]string)} }
func (ch *ConsistentHash) hash(key string) int { h := 0; for _, c := range key { h = int(c) + (h << 6) + (h << 16) - h }; if h < 0 { h = -h }; return h }
func (ch *ConsistentHash) AddNode(node string) {
    ch.mu.Lock(); defer ch.mu.Unlock()
    for i := 0; i < ch.replicas; i++ { h := ch.hash(fmt.Sprintf("%s:%d", node, i)); ch.ring[h] = node; ch.sortedKeys = append(ch.sortedKeys, h) }
    sort.Ints(ch.sortedKeys)
}
func (ch *ConsistentHash) RemoveNode(node string) {
    ch.mu.Lock(); defer ch.mu.Unlock()
    for i := 0; i < ch.replicas; i++ { h := ch.hash(fmt.Sprintf("%s:%d", node, i)); delete(ch.ring, h); for j, k := range ch.sortedKeys { if k == h { ch.sortedKeys = append(ch.sortedKeys[:j], ch.sortedKeys[j+1:]...); break } } }
}
func (ch *ConsistentHash) GetNode(key string) string {
    ch.mu.RLock(); defer ch.mu.RUnlock()
    if len(ch.ring) == 0 { return "" }
    h := ch.hash(key); idx := sort.Search(len(ch.sortedKeys), func(i int) bool { return ch.sortedKeys[i] >= h })
    if idx == len(ch.sortedKeys) { idx = 0 }; return ch.ring[ch.sortedKeys[idx]]
}

import hashlib
class MerkleTree:
    def __init__(self, data):
        self.leaves = [self._hash(d) for d in data]
        self.root = self._build(self.leaves)
    def _hash(self, data): return hashlib.sha256(str(data).encode()).hexdigest()
    def _build(self, nodes):
        if len(nodes) == 1: return nodes[0]
        new_level = []
        for i in range(0, len(nodes), 2):
            if i + 1 < len(nodes): new_level.append(self._hash(nodes[i] + nodes[i+1]))
            else: new_level.append(nodes[i])
        return self._build(new_level)

class MerkleTree {
    constructor(data) { this.leaves = data.map(d => this.hash(d)); this.root = this.build(this.leaves); }
    hash(data) { let h = 0; const s = String(data); for (let i = 0; i < s.length; i++) h = ((h << 5) - h) + s.charCodeAt(i) | 0; return Math.abs(h).toString(16); }
    build(nodes) {
        if (nodes.length === 1) return nodes[0];
        const newLevel = [];
        for (let i = 0; i < nodes.length; i += 2) { if (i + 1 < nodes.length) newLevel.push(this.hash(nodes[i] + nodes[i+1])); else newLevel.push(nodes[i]); }
        return this.build(newLevel);
    }
}

public class MerkleTree {
    private String root;
    public MerkleTree(List<String> data) { List<String> leaves = data.stream().map(this::hash).collect(Collectors.toList()); this.root = build(leaves); }
    private String hash(String data) {
        try { MessageDigest md = MessageDigest.getInstance("SHA-256"); StringBuilder sb = new StringBuilder(); for (byte b : md.digest(data.getBytes())) sb.append(String.format("%02x", b)); return sb.toString(); }
        catch (Exception e) { return null; }
    }
    private String build(List<String> nodes) {
        if (nodes.size() == 1) return nodes.get(0);
        List<String> newLevel = new ArrayList<>();
        for (int i = 0; i < nodes.size(); i += 2) { if (i + 1 < nodes.size()) newLevel.add(hash(nodes.get(i) + nodes.get(i + 1))); else newLevel.add(nodes.get(i)); }
        return build(newLevel);
    }
    public String getRoot() { return root; }
}

class RaftLog:
