import random
class GossipProtocol:
    def __init__(self, node_id, peers): self.node_id = node_id; self.peers = peers; self.messages = set()
    def receive(self, message):
        if message in self.messages: return False
        self.messages.add(message); self._gossip(message); return True
    def _gossip(self, message):
        sample = random.sample([p for p in self.peers if p != self.node_id], min(3, len(self.peers)))
        for peer in sample: peer.receive(message)

class GossipProtocol {
    constructor(nodeId, peers) { this.nodeId = nodeId; this.peers = peers; this.messages = new Set(); }
    receive(message) { if (this.messages.has(message)) return false; this.messages.add(message); this.gossip(message); return true; }
    gossip(message) {
        const candidates = this.peers.filter(p => p.nodeId !== this.nodeId);
        for (let i = candidates.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [candidates[i], candidates[j]] = [candidates[j], candidates[i]]; }
        candidates.slice(0, 3).forEach(p => p.receive(message));
    }
}

type GossipProtocol struct { nodeID string; peers []*GossipProtocol; messages map[string]bool; mu sync.Mutex }
func NewGossipProtocol(nodeID string, peers []*GossipProtocol) *GossipProtocol { return &GossipProtocol{nodeID: nodeID, peers: peers, messages: make(map[string]bool)} }
func (g *GossipProtocol) Receive(message string) bool {
    g.mu.Lock(); if g.messages[message] { g.mu.Unlock(); return false }; g.messages[message] = true; g.mu.Unlock()
    g.gossip(message); return true
}
func (g *GossipProtocol) gossip(message string) {
    candidates := make([]*GossipProtocol, 0)
    for _, p := range g.peers { if p.nodeID != g.nodeID { candidates = append(candidates, p) } }
    rand.Shuffle(len(candidates), func(i, j int) { candidates[i], candidates[j] = candidates[j], candidates[i] })
    n := 3; if len(candidates) < n { n = len(candidates) }; for _, p := range candidates[:n] { p.Receive(message) }
}

class TwoPhaseCommit:
    def __init__(self, participants): self.participants = participants
    def execute(self, transaction):
        for p in self.participants:
            if not p.prepare(transaction): self._abort(transaction); return False
        for p in self.participants: p.commit(transaction)
        return True
    def _abort(self, transaction):
        for p in self.participants: p.abort(transaction)

class TwoPhaseCommit {
    constructor(participants) { this.participants = participants; }
    execute(transaction) { for (const p of this.participants) { if (!p.prepare(transaction)) { this.abort(transaction); return false; } } for (const p of this.participants) p.commit(transaction); return true; }
    abort(transaction) { for (const p of this.participants) p.abort(transaction); }
}

