class VectorClock:
    def __init__(self): self.clock = {}
    def increment(self, node): self.clock[node] = self.clock.get(node, 0) + 1
    def update(self, other):
        for node, ts in other.clock.items(): self.clock[node] = max(self.clock.get(node, 0), ts)
    def get(self, node): return self.clock.get(node, 0)
    def __eq__(self, other): return self.clock == other.clock
    def __lt__(self, other): return all(self.clock.get(k, 0) <= v for k, v in other.clock.items()) and self.clock != other.clock

class VectorClock {
    constructor() { this.clock = {}; }
    increment(node) { this.clock[node] = (this.clock[node] || 0) + 1; }
    update(other) { for (const [node, ts] of Object.entries(other.clock)) { this.clock[node] = Math.max(this.clock[node] || 0, ts); } }
    get(node) { return this.clock[node] || 0; }
    equals(other) { const allKeys = new Set([...Object.keys(this.clock), ...Object.keys(other.clock)]); return [...allKeys].every(k => this.get(k) === other.get(k)); }
    lessThan(other) { const allKeys = new Set([...Object.keys(this.clock), ...Object.keys(other.clock)]); return [...allKeys].every(k => this.get(k) <= other.get(k)) && !this.equals(other); }
}

