class LSMTree:
    def __init__(self): self.memtable = {}; self.sstables = []
    def put(self, key, value):
        self.memtable[key] = value
        if len(self.memtable) >= 3: self.flush()
    def get(self, key):
        if key in self.memtable: return self.memtable[key]
        for table in reversed(self.sstables):
            if key in table: return table[key]
        return None
    def flush(self):
        self.sstables.append(dict(sorted(self.memtable.items()))); self.memtable = {}

class LSMTree {
    constructor() { this.memtable = {}; this.sstables = []; }
    put(key, value) { this.memtable[key] = value; if (Object.keys(this.memtable).length >= 3) this.flush(); }
    get(key) { if (key in this.memtable) return this.memtable[key]; for (let i = this.sstables.length - 1; i >= 0; i--) { if (key in this.sstables[i]) return this.sstables[i][key]; } return null; }
    flush() { const sorted = Object.keys(this.memtable).sort().reduce((acc, k) => { acc[k] = this.memtable[k]; return acc; }, {}); this.sstables.push(sorted); this.memtable = {}; }
}

