func (lsm *LSMTree) Get(key string) string {
    lsm.mu.Lock(); defer lsm.mu.Unlock()
    if v, ok := lsm.memtable[key]; ok { return v }
    for i := len(lsm.sstables) - 1; i >= 0; i-- { if v, ok := lsm.sstables[i][key]; ok { return v } }
    return ""
}
func (lsm *LSMTree) flush() {
    keys := make([]string, 0, len(lsm.memtable)); for k := range lsm.memtable { keys = append(keys, k) }; sort.Strings(keys)
    sorted := make(map[string]string); for _, k := range keys { sorted[k] = lsm.memtable[k] }
    lsm.sstables = append(lsm.sstables, sorted); lsm.memtable = make(map[string]string)
}

