        if node is None: node = self.root
        i = 0
        while i < len(node.keys) and key > node.keys[i]: i += 1
        if i < len(node.keys) and key == node.keys[i]: return (node, i)
        if node.leaf: return None
        return self.search(key, node.children[i])

