}

class SegmentTree:
    def __init__(self, arr):
        self.n = len(arr); self.tree = [0] * (4 * self.n)
        self._build(arr, 0, 0, self.n - 1)
    def _build(self, arr, node, l, r):
        if l == r: self.tree[node] = arr[l]; return
        mid = (l + r) // 2
        self._build(arr, 2*node+1, l, mid); self._build(arr, 2*node+2, mid+1, r)
        self.tree[node] = self.tree[2*node+1] + self.tree[2*node+2]
    def query(self, ql, qr, node=0, l=0, r=None):
        if r is None: r = self.n - 1
        if ql > r or qr < l: return 0
        if ql <= l and r <= qr: return self.tree[node]
        mid = (l + r) // 2
        return self.query(ql, qr, 2*node+1, l, mid) + self.query(ql, qr, 2*node+2, mid+1, r)
    def update(self, idx, val, node=0, l=0, r=None):
        if r is None: r = self.n - 1
        if l == r: self.tree[node] = val; return
        mid = (l + r) // 2
        if idx <= mid: self.update(idx, val, 2*node+1, l, mid)
        else: self.update(idx, val, 2*node+2, mid+1, r)
        self.tree[node] = self.tree[2*node+1] + self.tree[2*node+2]

class SegmentTree {
    constructor(arr) { this.n = arr.length; this.tree = new Array(4 * this.n).fill(0); this.build(arr, 0, 0, this.n - 1); }
    build(arr, node, l, r) {
        if (l === r) { this.tree[node] = arr[l]; return; }
        const mid = Math.floor((l + r) / 2);
        this.build(arr, 2*node+1, l, mid); this.build(arr, 2*node+2, mid+1, r);
        this.tree[node] = this.tree[2*node+1] + this.tree[2*node+2];
    }
    query(ql, qr, node = 0, l = 0, r = null) {
        if (r === null) r = this.n - 1;
        if (ql > r || qr < l) return 0;
        if (ql <= l && r <= qr) return this.tree[node];
        const mid = Math.floor((l + r) / 2);
        return this.query(ql, qr, 2*node+1, l, mid) + this.query(ql, qr, 2*node+2, mid+1, r);
    }
    update(idx, val, node = 0, l = 0, r = null) {
        if (r === null) r = this.n - 1;
        if (l === r) { this.tree[node] = val; return; }
        const mid = Math.floor((l + r) / 2);
        if (idx <= mid) this.update(idx, val, 2*node+1, l, mid);
        else this.update(idx, val, 2*node+2, mid+1, r);
        this.tree[node] = this.tree[2*node+1] + this.tree[2*node+2];
    }
}

public class SegmentTree {
    private int[] tree; private int n;
    public SegmentTree(int[] arr) { this.n = arr.length; this.tree = new int[4 * n]; build(arr, 0, 0, n - 1); }
    private void build(int[] arr, int node, int l, int r) {
        if (l == r) { tree[node] = arr[l]; return; }
        int mid = l + (r - l) / 2;
        build(arr, 2*node+1, l, mid); build(arr, 2*node+2, mid+1, r);
        tree[node] = tree[2*node+1] + tree[2*node+2];
    }
    public int query(int ql, int qr) { return query(ql, qr, 0, 0, n - 1); }
    private int query(int ql, int qr, int node, int l, int r) {
        if (ql > r || qr < l) return 0;
        if (ql <= l && r <= qr) return tree[node];
        int mid = l + (r - l) / 2;
        return query(ql, qr, 2*node+1, l, mid) + query(ql, qr, 2*node+2, mid+1, r);
    }
    public void update(int idx, int val) { update(idx, val, 0, 0, n - 1); }
    private void update(int idx, int val, int node, int l, int r) {
        if (l == r) { tree[node] = val; return; }
        int mid = l + (r - l) / 2;
        if (idx <= mid) update(idx, val, 2*node+1, l, mid);
        else update(idx, val, 2*node+2, mid+1, r);
        tree[node] = tree[2*node+1] + tree[2*node+2];
    }
}

class FenwickTree:
    def __init__(self, n): self.n = n; self.bit = [0] * (n + 1)
    def update(self, idx, delta):
        i = idx
        while i <= self.n: self.bit[i] += delta; i += i & -i
    def query(self, idx):
        result = 0; i = idx
        while i > 0: result += self.bit[i]; i -= i & -i
        return result
    def range_query(self, l, r): return self.query(r) - self.query(l - 1)

class FenwickTree {
    constructor(n) { this.n = n; this.bit = new Array(n + 1).fill(0); }
    update(idx, delta) { let i = idx; while (i <= this.n) { this.bit[i] += delta; i += i & -i; } }
    query(idx) { let result = 0, i = idx; while (i > 0) { result += this.bit[i]; i -= i & -i; } return result; }
    rangeQuery(l, r) { return this.query(r) - this.query(l - 1); }
}

