func (ft *FenwickTree) RangeQuery(l, r int) int { return ft.Query(r) - ft.Query(l-1) }

function rabinKarp(text, pattern) {
    const n = text.length, m = pattern.length;
    if (m > n) return -1;
    const base = 256, mod = 101;
    let hpat = 0, htxt = 0, h = 1;
    for (let i = 0; i < m - 1; i++) h = (h * base) % mod;
    for (let i = 0; i < m; i++) { hpat = (base * hpat + pattern.charCodeAt(i)) % mod; htxt = (base * htxt + text.charCodeAt(i)) % mod; }
    for (let i = 0; i <= n - m; i++) {
        if (htxt === hpat) { if (text.substring(i, i + m) === pattern) return i; }
        if (i < n - m) { htxt = (base * (htxt - text.charCodeAt(i) * h) + text.charCodeAt(i + m)) % mod; if (htxt < 0) htxt += mod; }
    }
    return -1;
}

public static int rabinKarp(String text, String pattern) {
