    for (int i = 0; i < m - 1; i++) h = (h * base) % mod;
    int hpat = 0, htxt = 0;
    for (int i = 0; i < m; i++) { hpat = (base * hpat + pattern.charAt(i)) % mod; htxt = (base * htxt + text.charAt(i)) % mod; }
    for (int i = 0; i <= n - m; i++) {
        if (htxt == hpat && text.substring(i, i + m).equals(pattern)) return i;
        if (i < n - m) { htxt = (base * (htxt - text.charAt(i) * h) + text.charAt(i + m)) % mod; if (htxt < 0) htxt += mod; }
    }
    return -1;
}

function kmp(text, pattern) {
    const m = pattern.length, n = text.length;
    const lps = new Array(m).fill(0); let j = 0;
    for (let i = 1; i < m; i++) {
        while (j > 0 && pattern[i] !== pattern[j]) j = lps[j - 1];
        if (pattern[i] === pattern[j]) { j++; lps[i] = j; }
    }
    j = 0;
    for (let i = 0; i < n; i++) {
        while (j > 0 && text[i] !== pattern[j]) j = lps[j - 1];
        if (text[i] === pattern[j]) j++;
        if (j === m) return i - m + 1;
    }
    return -1;
}

func KMP(text, pattern string) int {
    m, n := len(pattern), len(text)
    lps := make([]int, m); j := 0
    for i := 1; i < m; i++ {
        for j > 0 && pattern[i] != pattern[j] { j = lps[j-1] }
        if pattern[i] == pattern[j] { j++; lps[i] = j }
    }
    j = 0
    for i := 0; i < n; i++ {
        for j > 0 && text[i] != pattern[j] { j = lps[j-1] }
        if text[i] == pattern[j] { j++ }
        if j == m { return i - m + 1 }
    }
    return -1
}

def z_algorithm(s):
    n = len(s); z = [0] * n; l = r = 0
    for i in range(1, n):
        if i <= r: z[i] = min(r - i + 1, z[i - l])
        while i + z[i] < n and s[z[i]] == s[i + z[i]]: z[i] += 1
        if i + z[i] - 1 > r: l, r = i, i + z[i] - 1
    return z
def z_search(text, pattern):
