def manacher(s):
    t = '#' + '#'.join(s) + '#'
    n = len(t); p = [0] * n; center = right = 0
    for i in range(n):
        if i < right: p[i] = min(right - i, p[2 * center - i])
        while i - p[i] - 1 >= 0 and i + p[i] + 1 < n and t[i - p[i] - 1] == t[i + p[i] + 1]: p[i] += 1
        if i + p[i] > right: center, right = i, i + p[i]
    max_len = max(p); ci = p.index(max_len)
    start = (ci - max_len) // 2
    return s[start:start + max_len]

function manacher(s) {
    const t = '#' + s.split('').join('#') + '#';
    const n = t.length; const p = new Array(n).fill(0); let center = 0, right = 0;
    for (let i = 0; i < n; i++) {
        if (i < right) p[i] = Math.min(right - i, p[2 * center - i]);
        while (i - p[i] - 1 >= 0 && i + p[i] + 1 < n && t[i - p[i] - 1] === t[i + p[i] + 1]) p[i]++;
        if (i + p[i] > right) { center = i; right = i + p[i]; }
    }
    const maxLen = Math.max(...p); const ci = p.indexOf(maxLen);
    const start = Math.floor((ci - maxLen) / 2);
    return s.substring(start, start + maxLen);
}

public static String manacher(String s) {
    StringBuilder sb = new StringBuilder("#");
