    String t = sb.toString(); int n = t.length();
    int[] p = new int[n]; int center = 0, right = 0;
    for (int i = 0; i < n; i++) {
        if (i < right) p[i] = Math.min(right - i, p[2 * center - i]);
        while (i - p[i] - 1 >= 0 && i + p[i] + 1 < n && t.charAt(i - p[i] - 1) == t.charAt(i + p[i] + 1)) p[i]++;
        if (i + p[i] > right) { center = i; right = i + p[i]; }
    }
    int maxLen = 0, ci = 0;
    for (int i = 0; i < n; i++) { if (p[i] > maxLen) { maxLen = p[i]; ci = i; } }
    int start = (ci - maxLen) / 2;
    return s.substring(start, start + maxLen);
}

import heapq
def a_star(start, goal, h, neighbors):
    open_set = [(0, start)]; g_score = {start: 0}; came_from = {}
    while open_set:
        _, current = heapq.heappop(open_set)
        if current == goal:
            path = []
            while current in came_from: path.append(current); current = came_from[current]
            path.append(start); return path[::-1]
        for neighbor, cost in neighbors(current):
            tg = g_score[current] + cost
            if neighbor not in g_score or tg < g_score[neighbor]:
                g_score[neighbor] = tg
                heapq.heappush(open_set, (tg + h(neighbor, goal), neighbor))
                came_from[neighbor] = current
    return None

function aStar(start, goal, h, neighbors) {
    const openSet = [{ f: 0, node: start }]; const gScore = new Map([[start, 0]]); const cameFrom = new Map();
    while (openSet.length) {
        openSet.sort((a, b) => a.f - b.f);
        const current = openSet.shift().node;
        if (current === goal) { const path = []; let c = current; while (cameFrom.has(c)) { path.push(c); c = cameFrom.get(c); } path.push(start); return path.reverse(); }
        for (const [neighbor, cost] of neighbors(current)) {
            const tg = gScore.get(current) + cost;
            if (!gScore.has(neighbor) || tg < gScore.get(neighbor)) { gScore.set(neighbor, tg); cameFrom.set(neighbor, current); openSet.push({ f: tg + h(neighbor, goal), node: neighbor }); }
        }
    }
    return null;
}

public static List<String> aStar(String start, String goal, BiFunction<String, String, Double> h, Function<String, List<AbstractMap.SimpleEntry<String, Double>>> neighbors) {
    PriorityQueue<AbstractMap.SimpleEntry<Double, String>> openSet = new PriorityQueue<>(Comparator.comparingDouble(Map.Entry::getKey));
    openSet.offer(new AbstractMap.SimpleEntry<>(0.0, start));
    Map<String, Double> gScore = new HashMap<>(); gScore.put(start, 0.0);
    Map<String, String> cameFrom = new HashMap<>();
    while (!openSet.isEmpty()) {
        String current = openSet.poll().getValue();
        if (current.equals(goal)) { LinkedList<String> path = new LinkedList<>(); for (String c = current; c != null; c = cameFrom.get(c)) path.addFirst(c); return path; }
        for (var entry : neighbors.apply(current)) {
            String neighbor = entry.getKey(); double cost = entry.getValue();
            double tg = gScore.get(current) + cost;
            if (!gScore.containsKey(neighbor) || tg < gScore.get(neighbor)) { gScore.put(neighbor, tg); cameFrom.put(neighbor, current); openSet.offer(new AbstractMap.SimpleEntry<>(tg + h.apply(neighbor, goal), neighbor)); }
        }
    }
    return null;
}

function minimax(board, depth, isMaximizing) {
    const score = evaluate(board);
    if (score !== null) return score;
    if (isMaximizing) {
        let best = -Infinity;
        for (const move of getMoves(board)) { board[move] = 'X'; best = Math.max(best, minimax(board, depth + 1, false)); board[move] = null; }
        return best;
    } else {
        let best = Infinity;
        for (const move of getMoves(board)) { board[move] = 'O'; best = Math.min(best, minimax(board, depth + 1, true)); board[move] = null; }
        return best;
    }
}

func Minimax(board []string, depth int, isMaximizing bool) int {
    score := evaluate(board)
    if score != nil { return *score }
    if isMaximizing {
        best := -1 << 31
        for _, move := range getMoves(board) { board[move] = "X"; val := Minimax(board, depth+1, false); board[move] = ""; if val > best { best = val } }
        return best
    } else {
        best := 1 << 31
        for _, move := range getMoves(board) { board[move] = "O"; val := Minimax(board, depth+1, true); board[move] = ""; if val < best { best = val } }
        return best
    }
}

function alphaBeta(board, depth, alpha, beta, isMaximizing) {
    const score = evaluate(board);
    if (score !== null) return score;
    if (isMaximizing) {
        let best = -Infinity;
        for (const move of getMoves(board)) { board[move] = 'X'; best = Math.max(best, alphaBeta(board, depth + 1, alpha, beta, false)); board[move] = null; alpha = Math.max(alpha, best); if (beta <= alpha) break; }
        return best;
    } else {
        let best = Infinity;
        for (const move of getMoves(board)) { board[move] = 'O'; best = Math.min(best, alphaBeta(board, depth + 1, alpha, beta, true)); board[move] = null; beta = Math.min(beta, best); if (beta <= alpha) break; }
        return best;
    }
}

func AlphaBeta(board []string, depth int, alpha, beta float64, isMaximizing bool) float64 {
    score := evaluate(board)
    if score != nil { return *score }
    if isMaximizing {
        best := -math.MaxFloat64
        for _, move := range getMoves(board) { board[move] = "X"; val := AlphaBeta(board, depth+1, alpha, beta, false); board[move] = ""; if val > best { best = val }; if best > alpha { alpha = best }; if beta <= alpha { break } }
        return best
    } else {
        best := math.MaxFloat64
        for _, move := range getMoves(board) { board[move] = "O"; val := AlphaBeta(board, depth+1, alpha, beta, true); board[move] = ""; if val < best { best = val }; if best < beta { beta = best }; if beta <= alpha { break } }
        return best
    }
}

function simulatedAnnealing(initial, costFunc, neighborFunc, temp, coolingRate) {
    let current = initial, currentCost = costFunc(current);
    let best = current, bestCost = currentCost;
    while (temp > 0.01) {
        const neighbor = neighborFunc(current); const nc = costFunc(neighbor);
        const delta = nc - currentCost;
        if (delta < 0 || Math.random() < Math.exp(-delta / temp)) { current = neighbor; currentCost = nc; if (currentCost < bestCost) { best = current; bestCost = currentCost; } }
        temp *= coolingRate;
    }
    return [best, bestCost];
}

public static double[] simulatedAnnealing(double[] initial, Function<double[], Double> costFunc, UnaryOperator<double[]> neighborFunc, double temp, double coolingRate) {
    double[] current = initial.clone(); double currentCost = costFunc.apply(current);
    double[] best = current.clone(); double bestCost = currentCost; Random rand = new Random();
    while (temp > 0.01) {
        double[] neighbor = neighborFunc.apply(current); double nc = costFunc.apply(neighbor);
        double delta = nc - currentCost;
        if (delta < 0 || rand.nextDouble() < Math.exp(-delta / temp)) { current = neighbor; currentCost = nc; if (currentCost < bestCost) { best = current.clone(); bestCost = currentCost; } }
        temp *= coolingRate;
    }
    return new double[]{best[0], bestCost};
}

import random
def genetic_algorithm(population, fitness_func, mutate_func, crossover_func, generations):
    for _ in range(generations):
        scored = [(fitness_func(ind), ind) for ind in population]
        scored.sort(key=lambda x: x[0], reverse=True)
        new_pop = [ind for _, ind in scored[:2]]
        while len(new_pop) < len(population):
            p1 = random.choice(population); p2 = random.choice(population)
            child = crossover_func(p1, p2)
            if random.random() < 0.1: child = mutate_func(child)
            new_pop.append(child)
        population = new_pop
    return max(population, key=fitness_func)

function geneticAlgorithm(population, fitnessFunc, mutateFunc, crossoverFunc, generations) {
    for (let gen = 0; gen < generations; gen++) {
        const scored = population.map(ind => ({ fitness: fitnessFunc(ind), ind }));
        scored.sort((a, b) => b.fitness - a.fitness);
        const newPop = scored.slice(0, 2).map(s => s.ind);
        while (newPop.length < population.length) {
            const p1 = population[Math.floor(Math.random() * population.length)];
            const p2 = population[Math.floor(Math.random() * population.length)];
            let child = crossoverFunc(p1, p2);
            if (Math.random() < 0.1) child = mutateFunc(child);
            newPop.push(child);
        }
        population = newPop;
    }
    return population.reduce((best, ind) => fitnessFunc(ind) > fitnessFunc(best) ? ind : best);
}

func GeneticAlgorithm(population []string, fitness func(string) int, mutate func(string) string, crossover func(string, string) string, generations int) string {
    for gen := 0; gen < generations; gen++ {
        sort.Slice(population, func(i, j int) bool { return fitness(population[i]) > fitness(population[j]) })
        newPop := []string{population[0], population[1]}
        for len(newPop) < len(population) {
            p1 := population[rand.Intn(len(population))]; p2 := population[rand.Intn(len(population))]
            child := crossover(p1, p2)
            if rand.Float64() < 0.1 { child = mutate(child) }
            newPop = append(newPop, child)
        }
        population = newPop
    }
    best := population[0]
    for _, ind := range population { if fitness(ind) > fitness(best) { best = ind } }
    return best
}

import random
def k_means(data, k, max_iter=100):
    centroids = random.sample(data, k)
    for _ in range(max_iter):
        clusters = [[] for _ in range(k)]
        for point in data:
            distances = [sum((point[i] - c[i])**2 for i in range(len(point))) for c in centroids]
            clusters[distances.index(min(distances))].append(point)
        new_centroids = []
        for cluster in clusters:
            if cluster: new_centroids.append([sum(p[i] for p in cluster)/len(cluster) for i in range(len(cluster[0]))])
            else: new_centroids.append(random.sample(data, 1)[0])
        if new_centroids == centroids: break
        centroids = new_centroids
    return centroids, clusters

function kMeans(data, k, maxIter = 100) {
    let centroids = data.slice(0, k);
    for (let iter = 0; iter < maxIter; iter++) {
        const clusters = Array.from({length: k}, () => []);
        for (const point of data) {
            const dists = centroids.map(c => Math.sqrt(c.reduce((s, v, i) => s + (v - point[i]) ** 2, 0)));
            clusters[dists.indexOf(Math.min(...dists))].push(point);
        }
        const newCentroids = clusters.map(c => { if (!c.length) return data[Math.floor(Math.random() * data.length)]; return c[0].map((_, i) => c.reduce((s, p) => s + p[i], 0) / c.length); });
        if (JSON.stringify(newCentroids) === JSON.stringify(centroids)) break;
        centroids = newCentroids;
    }
    return centroids;
}

public static double[][] kMeans(double[][] data, int k, int maxIter) {
    Random rand = new Random(); double[][] centroids = Arrays.copyOf(data, k);
    for (int iter = 0; iter < maxIter; iter++) {
        List<List<double[]>> clusters = new ArrayList<>(); for (int i = 0; i < k; i++) clusters.add(new ArrayList<>());
        for (double[] point : data) {
            int nearest = 0; double minDist = Double.MAX_VALUE;
            for (int j = 0; j < k; j++) { double dist = 0; for (int d = 0; d < point.length; d++) dist += Math.pow(point[d] - centroids[j][d], 2); if (dist < minDist) { minDist = dist; nearest = j; } }
            clusters.get(nearest).add(point);
        }
        double[][] newCentroids = new double[k][data[0].length];
        for (int j = 0; j < k; j++) {
            if (clusters.get(j).isEmpty()) { newCentroids[j] = data[rand.nextInt(data.length)]; continue; }
            for (int d = 0; d < data[0].length; d++) { final int dim = d; newCentroids[j][d] = clusters.get(j).stream().mapToDouble(p -> p[dim]).average().orElse(0); }
        }
        if (Arrays.deepEquals(newCentroids, centroids)) break;
        centroids = newCentroids;
    }
    return centroids;
}

function knn(trainData, trainLabels, testPoint, k) {
    const distances = trainData.map((point, i) => ({ dist: Math.sqrt(point.reduce((s, v, j) => s + (v - testPoint[j]) ** 2, 0)), label: trainLabels[i] }));
    distances.sort((a, b) => a.dist - b.dist);
    const nearest = distances.slice(0, k);
    const counts = {};
    nearest.forEach(n => { counts[n.label] = (counts[n.label] || 0) + 1; });
    return Object.keys(counts).reduce((a, b) => counts[a] > counts[b] ? a : b);
}

public static String knn(double[][] trainData, String[] trainLabels, double[] testPoint, int k) {
    PriorityQueue<AbstractMap.SimpleEntry<Double, String>> pq = new PriorityQueue<>(Comparator.comparingDouble(Map.Entry::getKey));
    for (int i = 0; i < trainData.length; i++) {
        double dist = 0; for (int j = 0; j < trainData[i].length; j++) dist += Math.pow(trainData[i][j] - testPoint[j], 2);
        pq.offer(new AbstractMap.SimpleEntry<>(Math.sqrt(dist), trainLabels[i]));
        if (pq.size() > k) pq.poll();
    }
    Map<String, Integer> counts = new HashMap<>();
    while (!pq.isEmpty()) { String label = pq.poll().getValue(); counts.put(label, counts.getOrDefault(label, 0) + 1); }
    return counts.entrySet().stream().max(Map.Entry.comparingByValue()).get().getKey();
}

import math
def naive_bayes(X, y, x_test):
    classes = set(y); n = len(y); probs = {}
    for c in classes:
        X_c = [X[i] for i in range(n) if y[i] == c]
        probs[c] = math.log(len(X_c) / n)
        for j in range(len(x_test)):
            mean = sum(row[j] for row in X_c) / len(X_c)
            var = sum((row[j] - mean)**2 for row in X_c) / len(X_c)
            prob = (1 / math.sqrt(2 * math.pi * var)) * math.exp(-(x_test[j] - mean)**2 / (2 * var)) if var > 0 else 1e-10
            probs[c] += math.log(prob)
    return max(probs, key=probs.get)

function naiveBayes(X, y, xTest) {
    const classes = [...new Set(y)]; const n = y.length; const probs = {};
    for (const c of classes) {
        const Xc = X.filter((_, i) => y[i] === c);
        probs[c] = Math.log(Xc.length / n);
        for (let j = 0; j < xTest.length; j++) {
            const mean = Xc.reduce((s, row) => s + row[j], 0) / Xc.length;
            const variance = Xc.reduce((s, row) => s + (row[j] - mean) ** 2, 0) / Xc.length;
            const varCorr = variance || 1e-10;
            probs[c] += Math.log((1 / Math.sqrt(2 * Math.PI * varCorr)) * Math.exp(-(xTest[j] - mean) ** 2 / (2 * varCorr)));
        }
    }
    return Object.keys(probs).reduce((a, b) => probs[a] > probs[b] ? a : b);
}

public static String naiveBayes(double[][] X, String[] y, double[] xTest) {
    Set<String> classes = new HashSet<>(Arrays.asList(y));
    Map<String, Double> probs = new HashMap<>(); int n = y.length;
    for (String c : classes) {
        List<double[]> Xc = new ArrayList<>();
        for (int i = 0; i < n; i++) { if (y[i].equals(c)) Xc.add(X[i]); }
        double logProb = Math.log((double) Xc.size() / n);
        for (int j = 0; j < xTest.length; j++) {
            final int dim = j;
            double mean = Xc.stream().mapToDouble(row -> row[dim]).average().orElse(0);
            double var = Xc.stream().mapToDouble(row -> Math.pow(row[dim] - mean, 2)).average().orElse(1e-10);
            if (var == 0) var = 1e-10;
            logProb += Math.log((1 / Math.sqrt(2 * Math.PI * var)) * Math.exp(-Math.pow(xTest[j] - mean, 2) / (2 * var)));
        }
        probs.put(c, logProb);
    }
    return probs.entrySet().stream().max(Map.Entry.comparingByValue()).get().getKey();
}

import math, collections
def decision_tree_train(X, y, features):
    if len(set(y)) == 1: return y[0]
    if not features: return collections.Counter(y).most_common(1)[0][0]
    best_feat = min(features, key=lambda f: entropy_split(X, y, f))
    tree = {best_feat: {}}
    for val in set(X[i][best_feat] for i in range(len(X))):
        sub_X = [X[i] for i in range(len(X)) if X[i][best_feat] == val]
        sub_y = [y[i] for i in range(len(X)) if X[i][best_feat] == val]
        tree[best_feat][val] = decision_tree_train(sub_X, sub_y, [f for f in features if f != best_feat])
    return tree
def entropy_split(X, y, feat):
    total = len(y); result = 0
    for val in set(X[i][feat] for i in range(total)):
        sub_y = [y[i] for i in range(total) if X[i][feat] == val]
        p = len(sub_y) / total
        e = 0
        for c in set(sub_y):
            pc = sub_y.count(c) / len(sub_y)
            if pc > 0: e -= pc * math.log2(pc)
        result += p * e
    return result

function decisionTreeTrain(X, y, features) {
    if (new Set(y).size === 1) return y[0];
    if (features.length === 0) return y.reduce((a, b) => y.filter(v => v === a).length >= y.filter(v => v === b).length ? a : b);
    const bestFeat = features.reduce((a, b) => entropySplit(X, y, a) <= entropySplit(X, y, b) ? a : b);
    const tree = { [bestFeat]: {} };
    const vals = [...new Set(X.map(row => row[bestFeat]))];
    for (const val of vals) {
        const indices = X.map((row, i) => row[bestFeat] === val ? i : -1).filter(i => i !== -1);
        const subX = indices.map(i => X[i]); const subY = indices.map(i => y[i]);
        tree[bestFeat][val] = decisionTreeTrain(subX, subY, features.filter(f => f !== bestFeat));
    }
    return tree;
}
function entropySplit(X, y, feat) {
    let result = 0; const total = y.length;
    const vals = [...new Set(X.map(row => row[feat]))];
    for (const val of vals) {
        const subY = y.filter((_, i) => X[i][feat] === val);
        const p = subY.length / total;
        let e = 0; const classes = [...new Set(subY)];
        for (const c of classes) { const pc = subY.filter(v => v === c).length / subY.length; if (pc > 0) e -= pc * Math.log2(pc); }
        result += p * e;
    }
    return result;
}

public static Object decisionTreeTrain(double[][] X, String[] y, List<Integer> features) {
    Set<String> uniqueY = new HashSet<>(Arrays.asList(y));
    if (uniqueY.size() == 1) return y[0];
    if (features.isEmpty()) { Map<String, Long> count = Arrays.stream(y).collect(Collectors.groupingBy(Function.identity(), Collectors.counting())); return count.entrySet().stream().max(Map.Entry.comparingByValue()).get().getKey(); }
    int bestFeat = features.get(0); double bestEnt = Double.MAX_VALUE;
    for (int f : features) { double e = entropySplit(X, y, f); if (e < bestEnt) { bestEnt = e; bestFeat = f; } }
    Map<Double, Object> tree = new HashMap<>();
    Set<Double> vals = new HashSet<>(); for (double[] row : X) vals.add(row[bestFeat]);
    for (double val : vals) {
        List<Integer> indices = new ArrayList<>();
        for (int i = 0; i < X.length; i++) { if (X[i][bestFeat] == val) indices.add(i); }
        double[][] subX = new double[indices.size()][]; String[] subY = new String[indices.size()];
        for (int i = 0; i < indices.size(); i++) { subX[i] = X[indices.get(i)]; subY[i] = y[indices.get(i)]; }
        List<Integer> remaining = features.stream().filter(f -> f != bestFeat).collect(Collectors.toList());
        tree.put(val, decisionTreeTrain(subX, subY, remaining));
    }
    Map<Object, Object> result = new HashMap<>(); result.put(bestFeat, tree); return result;
}
private static double entropySplit(double[][] X, String[] y, int feat) {
    double result = 0; int total = y.length;
    Map<Double, List<Integer>> splits = new HashMap<>();
    for (int i = 0; i < total; i++) { splits.computeIfAbsent(X[i][feat], k -> new ArrayList<>()).add(i); }
    for (var entry : splits.entrySet()) {
        List<String> subY = entry.getValue().stream().map(i -> y[i]).collect(Collectors.toList());
        double p = (double) subY.size() / total;
        double e = 0; Map<String, Long> counts = subY.stream().collect(Collectors.groupingBy(Function.identity(), Collectors.counting()));
        for (long c : counts.values()) { double pc = (double) c / subY.size(); if (pc > 0) e -= pc * (Math.log(pc) / Math.log(2)); }
        result += p * e;
    }
    return result;
}

