function simpleTree(X, y, maxDepth, depth = 0) {
    if (new Set(y).size === 1 || depth >= maxDepth) return y.reduce((a, b) => y.filter(v => v === a).length >= y.filter(v => v === b).length ? a : b);
    const feat = Math.floor(Math.random() * X[0].length);
    const tree = { [feat]: {} };
    const vals = [...new Set(X.map(row => row[feat]))];
    for (const val of vals) {
        const indices = X.map((row, i) => row[feat] === val ? i : -1).filter(i => i !== -1);
        tree[feat][val] = simpleTree(indices.map(i => X[i]), indices.map(i => y[i]), maxDepth, depth + 1);
    }
    return tree;
}
function forestPredict(trees, x) {
    const votes = trees.map(tree => {
        let node = tree;
        while (typeof node === 'object') { const feat = parseInt(Object.keys(node)[0]); node = node[feat][x[feat]] || Object.values(node[feat])[0]; }
        return node;
    });
    return votes.reduce((a, b) => votes.filter(v => v === a).length >= votes.filter(v => v === b).length ? a : b);
}

public static List<Object> randomForest(double[][] X, String[] y, int nTrees, int maxDepth) {
    List<Object> trees = new ArrayList<>(); Random rand = new Random();
    for (int t = 0; t < nTrees; t++) {
        double[][] bx = new double[X.length][]; String[] by = new String[y.length];
        for (int i = 0; i < X.length; i++) { int idx = rand.nextInt(X.length); bx[i] = X[idx]; by[i] = y[idx]; }
        trees.add(simpleTree(bx, by, maxDepth, 0));
    }
    return trees;
}
private static Object simpleTree(double[][] X, String[] y, int maxDepth, int depth) {
    Set<String> unique = new HashSet<>(Arrays.asList(y));
    if (unique.size() == 1 || depth >= maxDepth) {
        Map<String, Long> count = Arrays.stream(y).collect(Collectors.groupingBy(Function.identity(), Collectors.counting()));
        return count.entrySet().stream().max(Map.Entry.comparingByValue()).get().getKey();
    }
    int feat = new Random().nextInt(X[0].length);
    Map<Object, Object> tree = new HashMap<>();
    Set<Double> vals = new HashSet<>(); for (double[] row : X) vals.add(row[feat]);
    for (double val : vals) {
        List<Integer> indices = new ArrayList<>();
        for (int i = 0; i < X.length; i++) { if (X[i][feat] == val) indices.add(i); }
        double[][] subX = new double[indices.size()][]; String[] subY = new String[indices.size()];
        for (int i = 0; i < indices.size(); i++) { subX[i] = X[indices.get(i)]; subY[i] = y[indices.get(i)]; }
        tree.put(val, simpleTree(subX, subY, maxDepth, depth + 1));
    }
    Map<Object, Object> result = new HashMap<>(); result.put(feat, tree); return result;
}
public static String forestPredict(List<Object> trees, double[] x) {
    List<String> votes = new ArrayList<>();
    for (Object tree : trees) {
        Object node = tree;
        while (node instanceof Map) { Map<Object, Object> m = (Map<Object, Object>) node; int feat = (int) m.keySet().iterator().next(); Map<Object, Object> branches = (Map<Object, Object>) m.get(feat); node = branches.getOrDefault(x[feat], branches.values().iterator().next()); }
        votes.add((String) node);
    }
    Map<String, Long> count = votes.stream().collect(Collectors.groupingBy(Function.identity(), Collectors.counting()));
    return count.entrySet().stream().max(Map.Entry.comparingByValue()).get().getKey();
}

function linearRegression(X, y) {
    const n = X.length; const mx = X.reduce((a, b) => a + b, 0) / n; const my = y.reduce((a, b) => a + b, 0) / n;
    let num = 0, den = 0;
    for (let i = 0; i < n; i++) { num += (X[i] - mx) * (y[i] - my); den += (X[i] - mx) ** 2; }
    const slope = num / den; const intercept = my - slope * mx;
    return { slope, intercept };
}

public static double[] linearRegression(double[] X, double[] y) {
    int n = X.length; double mx = Arrays.stream(X).average().orElse(0); double my = Arrays.stream(y).average().orElse(0);
    double num = 0, den = 0;
    for (int i = 0; i < n; i++) { num += (X[i] - mx) * (y[i] - my); den += (X[i] - mx) * (X[i] - mx); }
    double slope = num / den; double intercept = my - slope * mx;
    return new double[]{slope, intercept};
}

func LinearRegression(X, y []float64) (float64, float64) {
    n := len(X); mx, my := 0.0, 0.0
    for i := 0; i < n; i++ { mx += X[i]; my += y[i] }
    mx /= float64(n); my /= float64(n)
    var num, den float64
    for i := 0; i < n; i++ { num += (X[i] - mx) * (y[i] - my); den += (X[i] - mx) * (X[i] - mx) }
    slope := num / den; intercept := my - slope*mx
    return slope, intercept
}

function pca(X, nComponents) {
    const n = X.length, dims = X[0].length;
    const means = Array.from({length: dims}, (_, j) => X.reduce((s, row) => s + row[j], 0) / n);
    const stds = Array.from({length: dims}, (_, j) => Math.sqrt(X.reduce((s, row) => s + (row[j] - means[j]) ** 2, 0) / n));
    const Xstd = X.map(row => row.map((v, j) => (v - means[j]) / (stds[j] || 1)));
    const cov = Array.from({length: dims}, (_, i) => Array.from({length: dims}, (_, j) => Xstd.reduce((s, row) => s + row[i] * row[j], 0) / (n - 1)));
    const { vectors, values } = eigenDecomposition(cov);
    const indices = values.map((v, i) => i).sort((a, b) => values[b] - values[a]).slice(0, nComponents);
    return { components: indices.map(i => vectors[i]), values: indices.map(i => values[i]) };
}

public static double[][] pca(double[][] X, int nComponents) {
    int n = X.length, dims = X[0].length;
    double[] means = new double[dims]; double[] stds = new double[dims];
    for (int j = 0; j < dims; j++) { final int d = j; means[j] = Arrays.stream(X).mapToDouble(row -> row[d]).average().orElse(0); }
    for (int j = 0; j < dims; j++) { final int d = j; double m = means[j]; stds[j] = Math.sqrt(Arrays.stream(X).mapToDouble(row -> Math.pow(row[d] - m, 2)).average().orElse(0)); }
    double[][] Xstd = new double[n][dims];
    for (int i = 0; i < n; i++) for (int j = 0; j < dims; j++) Xstd[i][j] = (X[i][j] - means[j]) / (stds[j] == 0 ? 1 : stds[j]);
    double[][] cov = new double[dims][dims];
    for (int i = 0; i < dims; i++) for (int j = 0; j < dims; j++) { final int a = i, b = j; cov[i][j] = Arrays.stream(Xstd).mapToDouble(row -> row[a] * row[b]).average().orElse(0); }
    Jama.EigenvalueDecomposition eig = new Jama.EigenvalueDecomposition(new Jama.Matrix(cov));
    double[] eigVals = eig.getRealEigenvalues();
    double[][] eigVecs = eig.getV().getArray();
    Integer[] idx = new Integer[dims]; for (int i = 0; i < dims; i++) idx[i] = i;
    Arrays.sort(idx, (a, b) -> Double.compare(eigVals[b], eigVals[a]));
    double[][] result = new double[dims][nComponents];
    for (int i = 0; i < nComponents; i++) for (int j = 0; j < dims; j++) result[j][i] = eigVecs[j][idx[i]];
    return result;
}

import math
class LogisticRegression:
    def __init__(self, lr=0.01, epochs=1000):
        self.lr = lr; self.epochs = epochs; self.weights = None; self.bias = None
    def sigmoid(self, z): return 1 / (1 + math.exp(-z))
    def fit(self, X, y):
        n, m = len(X), len(X[0])
        self.weights = [0.0] * m; self.bias = 0.0
        for _ in range(self.epochs):
            for i in range(n):
                z = sum(self.weights[j] * X[i][j] for j in range(m)) + self.bias
                pred = self.sigmoid(z)
                error = pred - y[i]
                for j in range(m): self.weights[j] -= self.lr * error * X[i][j]
                self.bias -= self.lr * error
    def predict(self, X):
        z = sum(self.weights[j] * X[j] for j in range(len(X))) + self.bias
        return 1 if self.sigmoid(z) >= 0.5 else 0

class LogisticRegression {
    constructor(lr = 0.01, epochs = 1000) { this.lr = lr; this.epochs = epochs; this.weights = null; this.bias = 0; }
