class SVM:
    def __init__(self, lr=0.001, lambda_param=0.01, epochs=1000):
        self.lr = lr; self.lambda_param = lambda_param; self.epochs = epochs
        self.w = None; self.b = None
    def fit(self, X, y):
        n, m = len(X), len(X[0])
        self.w = [0.0] * m; self.b = 0
        y = [-1 if yi == 0 else 1 for yi in y]
        for _ in range(self.epochs):
            for i in range(n):
                cond = y[i] * (sum(self.w[j] * X[i][j] for j in range(m)) + self.b)
                if cond >= 1:
                    for j in range(m): self.w[j] -= self.lr * self.lambda_param * self.w[j]
                else:
                    for j in range(m): self.w[j] -= self.lr * (self.lambda_param * self.w[j] - y[i] * X[i][j])
                    self.b -= self.lr * y[i]
    def predict(self, X):
        z = sum(self.w[j] * X[j] for j in range(len(X))) + self.b
        return 1 if z >= 0 else 0

class SVM {
    constructor(lr = 0.001, lambdaParam = 0.01, epochs = 1000) { this.lr = lr; this.lambdaParam = lambdaParam; this.epochs = epochs; this.w = null; this.b = 0; }
    fit(X, y) {
        const n = X.length, m = X[0].length;
        this.w = new Array(m).fill(0); this.b = 0;
        const yb = y.map(v => v === 0 ? -1 : 1);
        for (let ep = 0; ep < this.epochs; ep++) {
            for (let i = 0; i < n; i++) {
                let z = this.b; for (let j = 0; j < m; j++) z += this.w[j] * X[i][j];
                const cond = yb[i] * z;
                if (cond >= 1) { for (let j = 0; j < m; j++) this.w[j] -= this.lr * this.lambdaParam * this.w[j]; }
                else { for (let j = 0; j < m; j++) this.w[j] -= this.lr * (this.lambdaParam * this.w[j] - yb[i] * X[i][j]); this.b -= this.lr * yb[i]; }
            }
        }
    }
    predict(X) { let z = this.b; for (let j = 0; j < X.length; j++) z += this.w[j] * X[j]; return z >= 0 ? 1 : 0; }
}

public class SVM {
    private double[] w; private double b; private double lr, lambdaParam; private int epochs;
    public SVM(double lr, double lambdaParam, int epochs) { this.lr = lr; this.lambdaParam = lambdaParam; this.epochs = epochs; }
    public void fit(double[][] X, int[] y) {
        int n = X.length, m = X[0].length;
        w = new double[m]; b = 0; int[] yb = new int[n]; for (int i = 0; i < n; i++) yb[i] = y[i] == 0 ? -1 : 1;
        for (int ep = 0; ep < epochs; ep++) {
            for (int i = 0; i < n; i++) {
                double z = b; for (int j = 0; j < m; j++) z += w[j] * X[i][j];
                double cond = yb[i] * z;
                if (cond >= 1) { for (int j = 0; j < m; j++) w[j] -= lr * lambdaParam * w[j]; }
                else { for (int j = 0; j < m; j++) w[j] -= lr * (lambdaParam * w[j] - yb[i] * X[i][j]); b -= lr * yb[i]; }
            }
        }
    }
    public int predict(double[] X) { double z = b; for (int j = 0; j < X.length; j++) z += w[j] * X[j]; return z >= 0 ? 1 : 0; }
}

def gradient_descent(gradient, start, learn_rate, n_iter):
    vector = start
    for _ in range(n_iter):
        vector -= learn_rate * gradient(vector)
    return vector

function gradientDescent(gradient, start, learnRate, nIter) {
    let vector = start;
    for (let i = 0; i < nIter; i++) { for (let j = 0; j < vector.length; j++) vector[j] -= learnRate * gradient(vector)[j]; }
    return vector;
}

func GradientDescent(gradient func([]float64) []float64, start []float64, learnRate float64, nIter int) []float64 {
    vector := make([]float64, len(start)); copy(vector, start)
    for i := 0; i < nIter; i++ {
        grad := gradient(vector)
        for j := range vector { vector[j] -= learnRate * grad[j] }
    }
    return vector
}

import math, random
class MLP:
    def __init__(self, layers):
        self.layers = layers; self.weights = []; self.biases = []
        for i in range(len(layers) - 1):
            self.weights.append([[random.uniform(-1, 1) for _ in range(layers[i])] for _ in range(layers[i+1])])
            self.biases.append([0.0] * layers[i+1])
    def sigmoid(self, x): return 1 / (1 + math.exp(-x))
    def forward(self, x):
        for l in range(len(self.weights)):
            x = [self.sigmoid(sum(self.weights[l][j][k] * x[k] for k in range(len(x))) + self.biases[l][j]) for j in range(len(self.weights[l]))]
        return x
    def train(self, X, y, epochs=100, lr=0.1):
        for _ in range(epochs):
            for xi, yi in zip(X, y):
                activations = [xi]; a = xi
                for l in range(len(self.weights)):
                    a = [self.sigmoid(sum(self.weights[l][j][k] * a[k] for k in range(len(a))) + self.biases[l][j]) for j in range(len(self.weights[l]))]
                    activations.append(a)
                errors = [yi[j] - a[j] for j in range(len(yi))]
                for l in reversed(range(len(self.weights))):
                    new_errors = [0] * len(self.weights[l-1]) if l > 0 else []
                    for j in range(len(self.weights[l])):
                        out = activations[l+1][j]
                        delta = errors[j] * out * (1 - out)
                        for k in range(len(self.weights[l][j])): self.weights[l][j][k] += lr * delta * activations[l][k]
                        self.biases[l][j] += lr * delta
                        if l > 0: new_errors[k] += delta * self.weights[l][j][k]
                    errors = new_errors

class MLP {
    constructor(layers) {
        this.layers = layers; this.weights = []; this.biases = [];
        for (let i = 0; i < layers.length - 1; i++) {
            this.weights.push(Array.from({length: layers[i+1]}, () => Array.from({length: layers[i]}, () => Math.random() * 2 - 1)));
            this.biases.push(new Array(layers[i+1]).fill(0));
        }
    }
    sigmoid(x) { return 1 / (1 + Math.exp(-x)); }
    forward(x) {
        let a = x;
        for (let l = 0; l < this.weights.length; l++) { a = this.weights[l].map((w, j) => this.sigmoid(w.reduce((s, v, k) => s + v * a[k], 0) + this.biases[l][j])); }
        return a;
    }
    train(X, y, epochs = 100, lr = 0.1) {
        for (let ep = 0; ep < epochs; ep++) {
            for (let i = 0; i < X.length; i++) {
                const activations = [X[i]]; let a = X[i];
                for (let l = 0; l < this.weights.length; l++) { a = this.weights[l].map((w, j) => this.sigmoid(w.reduce((s, v, k) => s + v * a[k], 0) + this.biases[l][j])); activations.push(a); }
                let errors = y[i].map((t, j) => t - a[j]);
                for (let l = this.weights.length - 1; l >= 0; l--) {
                    const newErrors = l > 0 ? new Array(this.weights[l-1].length).fill(0) : [];
                    for (let j = 0; j < this.weights[l].length; j++) {
                        const out = activations[l+1][j]; const delta = errors[j] * out * (1 - out);
                        for (let k = 0; k < this.weights[l][j].length; k++) { this.weights[l][j][k] += lr * delta * activations[l][k]; if (l > 0) newErrors[k] += delta * this.weights[l][j][k]; }
                        this.biases[l][j] += lr * delta;
                    }
                    errors = newErrors;
                }
            }
        }
    }
}

type MLP struct { layers []int; weights [][][]float64; biases [][]float64 }
func NewMLP(layers []int) *MLP {
    mlp := &MLP{layers: layers}
    for i := 0; i < len(layers)-1; i++ {
        w := make([][]float64, layers[i+1])
        for j := range w { w[j] = make([]float64, layers[i]); for k := range w[j] { w[j][k] = rand.Float64()*2 - 1 } }
        mlp.weights = append(mlp.weights, w)
        mlp.biases = append(mlp.biases, make([]float64, layers[i+1]))
    }
    return mlp
}
func (mlp *MLP) sigmoid(x float64) float64 { return 1.0 / (1.0 + math.Exp(-x)) }
func (mlp *MLP) Forward(x []float64) []float64 {
    a := make([]float64, len(x)); copy(a, x)
    for l := range mlp.weights {
        next := make([]float64, len(mlp.weights[l]))
        for j := range mlp.weights[l] {
            s := mlp.biases[l][j]
            for k := range mlp.weights[l][j] { s += mlp.weights[l][j][k] * a[k] }
            next[j] = mlp.sigmoid(s)
        }
        a = next
    }
    return a
}

import math
def collaborative_filtering(ratings, user, k=3):
    n_users = len(ratings); n_items = len(ratings[0])
    def cosine_sim(a, b):
        common = [(ratings[a][i], ratings[b][i]) for i in range(n_items) if ratings[a][i] > 0 and ratings[b][i] > 0]
        if not common: return 0
        dot = sum(x * y for x, y in common)
        na = math.sqrt(sum(x**2 for x, y in common))
        nb = math.sqrt(sum(y**2 for x, y in common))
        return dot / (na * nb) if na * nb > 0 else 0
    sims = [(cosine_sim(user, i), i) for i in range(n_users) if i != user]
    sims.sort(reverse=True)
    neighbors = sims[:k]
    scores = []
    for item in range(n_items):
        if ratings[user][item] == 0:
            num = sum(s * ratings[i][item] for s, i in neighbors if ratings[i][item] > 0)
            den = sum(s for s, i in neighbors if ratings[i][item] > 0)
            if den > 0: scores.append((item, num / den))
    return sorted(scores, key=lambda x: x[1], reverse=True)

function collaborativeFiltering(ratings, user, k = 3) {
    const nUsers = ratings.length, nItems = ratings[0].length;
    function cosineSim(a, b) {
        let dot = 0, na = 0, nb = 0;
        for (let i = 0; i < nItems; i++) { if (ratings[a][i] > 0 && ratings[b][i] > 0) { dot += ratings[a][i] * ratings[b][i]; na += ratings[a][i] ** 2; nb += ratings[b][i] ** 2; } }
        return na && nb ? dot / (Math.sqrt(na) * Math.sqrt(nb)) : 0;
    }
    const sims = [];
    for (let i = 0; i < nUsers; i++) { if (i !== user) sims.push({ sim: cosineSim(user, i), idx: i }); }
    sims.sort((a, b) => b.sim - a.sim);
    const neighbors = sims.slice(0, k);
    const scores = [];
    for (let item = 0; item < nItems; item++) {
        if (ratings[user][item] === 0) {
            let num = 0, den = 0;
            for (const n of neighbors) { if (ratings[n.idx][item] > 0) { num += n.sim * ratings[n.idx][item]; den += n.sim; } }
            if (den > 0) scores.push({ item, score: num / den });
        }
    }
    return scores.sort((a, b) => b.score - a.score);
}

func CollaborativeFiltering(ratings [][]float64, user, k int) []struct{ Item int; Score float64 } {
    nUsers, nItems := len(ratings), len(ratings[0])
    cosineSim := func(a, b int) float64 {
        var dot, na, nb float64
        for i := 0; i < nItems; i++ { if ratings[a][i] > 0 && ratings[b][i] > 0 { dot += ratings[a][i] * ratings[b][i]; na += ratings[a][i] * ratings[a][i]; nb += ratings[b][i] * ratings[b][i] } }
        if na == 0 || nb == 0 { return 0 }; return dot / (math.Sqrt(na) * math.Sqrt(nb))
    }
    type simT struct { s float64; idx int }
    var sims []simT
    for i := 0; i < nUsers; i++ { if i != user { sims = append(sims, simT{cosineSim(user, i), i}) } }
    sort.Slice(sims, func(i, j int) bool { return sims[i].s > sims[j].s })
    if k > len(sims) { k = len(sims) }
    neighbors := sims[:k]
    var scores []struct{ Item int; Score float64 }
    for item := 0; item < nItems; item++ {
        if ratings[user][item] == 0 {
            var num, den float64
            for _, n := range neighbors { if ratings[n.idx][item] > 0 { num += n.s * ratings[n.idx][item]; den += n.s } }
            if den > 0 { scores = append(scores, struct{ Item int; Score float64 }{item, num / den}) }
        }
    }
    sort.Slice(scores, func(i, j int) bool { return scores[i].Score > scores[j].Score })
    return scores
}

function contentBasedFiltering(userProfile, items, itemFeatures, k = 3) {
    const scores = items.map((item, i) => {
        let dot = 0, nu = 0, ni = 0;
        for (let j = 0; j < userProfile.length; j++) { dot += userProfile[j] * itemFeatures[i][j]; nu += userProfile[j] ** 2; ni += itemFeatures[i][j] ** 2; }
        return { item, score: nu && ni ? dot / (Math.sqrt(nu) * Math.sqrt(ni)) : 0 };
    });
    return scores.sort((a, b) => b.score - a.score).slice(0, k);
}

public static List<AbstractMap.SimpleEntry<String, Double>> contentBasedFiltering(double[] userProfile, String[] items, double[][] itemFeatures, int k) {
    List<AbstractMap.SimpleEntry<String, Double>> scores = new ArrayList<>();
    for (int i = 0; i < items.length; i++) {
        double dot = 0, nu = 0, ni = 0;
        for (int j = 0; j < userProfile.length; j++) { dot += userProfile[j] * itemFeatures[i][j]; nu += userProfile[j] * userProfile[j]; ni += itemFeatures[i][j] * itemFeatures[i][j]; }
        double sim = nu > 0 && ni > 0 ? dot / (Math.sqrt(nu) * Math.sqrt(ni)) : 0;
        scores.add(new AbstractMap.SimpleEntry<>(items[i], sim));
    }
    scores.sort((a, b) -> Double.compare(b.getValue(), a.getValue()));
    return scores.subList(0, Math.min(k, scores.size()));
}

import math, random
def matrix_factorization(R, K, steps=5000, alpha=0.0002, beta=0.02):
    N = len(R); M = len(R[0])
    P = [[random.uniform(0, 0.1) for _ in range(K)] for _ in range(N)]
    Q = [[random.uniform(0, 0.1) for _ in range(K)] for _ in range(M)]
    for step in range(steps):
        for i in range(N):
            for j in range(M):
                if R[i][j] > 0:
                    eij = R[i][j] - sum(P[i][k] * Q[j][k] for k in range(K))
                    for k in range(K):
                        P[i][k] += alpha * (2 * eij * Q[j][k] - beta * P[i][k])
                        Q[j][k] += alpha * (2 * eij * P[i][k] - beta * Q[j][k])
    return P, Q

function matrixFactorization(R, K, steps = 5000, alpha = 0.0002, beta = 0.02) {
    const N = R.length, M = R[0].length;
    let P = Array.from({length: N}, () => Array.from({length: K}, () => Math.random() * 0.1));
    let Q = Array.from({length: M}, () => Array.from({length: K}, () => Math.random() * 0.1));
    for (let step = 0; step < steps; step++) {
        for (let i = 0; i < N; i++) {
            for (let j = 0; j < M; j++) {
                if (R[i][j] > 0) {
                    let eij = R[i][j];
                    for (let k = 0; k < K; k++) eij -= P[i][k] * Q[j][k];
                    for (let k = 0; k < K; k++) { P[i][k] += alpha * (2 * eij * Q[j][k] - beta * P[i][k]); Q[j][k] += alpha * (2 * eij * P[i][k] - beta * Q[j][k]); }
                }
            }
        }
    }
    return { P, Q };
}

func MatrixFactorization(R [][]float64, K int, steps int, alpha, beta float64) ([][]float64, [][]float64) {
    N, M := len(R), len(R[0])
    P := make([][]float64, N); Q := make([][]float64, M)
    for i := range P { P[i] = make([]float64, K); for k := range P[i] { P[i][k] = rand.Float64() * 0.1 } }
    for j := range Q { Q[j] = make([]float64, K); for k := range Q[j] { Q[j][k] = rand.Float64() * 0.1 } }
    for step := 0; step < steps; step++ {
        for i := 0; i < N; i++ {
            for j := 0; j < M; j++ {
                if R[i][j] > 0 {
                    eij := R[i][j]
                    for k := 0; k < K; k++ { eij -= P[i][k] * Q[j][k] }
                    for k := 0; k < K; k++ { P[i][k] += alpha * (2*eij*Q[j][k] - beta*P[i][k]); Q[j][k] += alpha * (2*eij*P[i][k] - beta*Q[j][k]) }
                }
            }
        }
