from collections import defaultdict
def apriori(transactions, min_support, min_confidence):
    item_counts = defaultdict(int)
    for trans in transactions:
        for item in trans: item_counts[item] += 1
    L1 = {item for item, count in item_counts.items() if count / len(transactions) >= min_support}
    freq_sets = [L1]; k = 2
    while freq_sets[-1]:
        candidates = set()
        prev = freq_sets[-1]
        prev_list = [set(s) if isinstance(s, frozenset) else {s} for s in prev]
        for i in range(len(prev_list)):
            for j in range(i + 1, len(prev_list)):
                union = prev_list[i] | prev_list[j]
                if len(union) == k: candidates.add(frozenset(union))
        freq = set()
        for cand in candidates:
            count = sum(1 for t in transactions if cand.issubset(t))
            if count / len(transactions) >= min_support: freq.add(cand)
        freq_sets.append(freq); k += 1
    rules = []
    for freq_set in [item for sublist in freq_sets for item in sublist]:
        if isinstance(freq_set, frozenset) and len(freq_set) > 1:
            for item in freq_set:
                antecedent = freq_set - {item}
                supp = sum(1 for t in transactions if freq_set.issubset(t)) / len(transactions)
                conf = sum(1 for t in transactions if freq_set.issubset(t)) / max(sum(1 for t in transactions if antecedent.issubset(t)), 1)
                if conf >= min_confidence: rules.append((antecedent, {item}, supp, conf))
    return rules

function apriori(transactions, minSupport, minConfidence) {
    const n = transactions.length;
    const itemCounts = {}; transactions.forEach(t => t.forEach(item => { itemCounts[item] = (itemCounts[item] || 0) + 1; }));
    let freqSets = [new Set(Object.keys(itemCounts).filter(item => itemCounts[item] / n >= minSupport))];
    let k = 2;
    while (freqSets[freqSets.length - 1].size > 0) {
        const prev = [...freqSets[freqSets.length - 1]];
        const candidates = new Set();
        for (let i = 0; i < prev.length; i++) {
            for (let j = i + 1; j < prev.length; j++) {
                const union = new Set([...prev[i]].concat([...prev[j]]));
                if (union.size === k) candidates.add(union);
            }
        }
        const freq = new Set();
        for (const cand of candidates) {
            const count = transactions.filter(t => [...cand].every(item => t.includes(item))).length;
            if (count / n >= minSupport) freq.add(cand);
        }
        freqSets.push(freq); k++;
    }
    const rules = [];
    for (const fs of freqSets.flat()) {
        if (fs instanceof Set && fs.size > 1) {
            for (const item of fs) {
                const antecedent = new Set([...fs].filter(x => x !== item));
                const supp = transactions.filter(t => [...fs].every(x => t.includes(x))).length / n;
                const antCount = transactions.filter(t => [...antecedent].every(x => t.includes(x))).length;
                const conf = antCount > 0 ? transactions.filter(t => [...fs].every(x => t.includes(x))).length / antCount : 0;
                if (conf >= minConfidence) rules.push({ antecedent, consequent: new Set([item]), support: supp, confidence: conf });
            }
        }
    }
    return rules;
}

public static List<String> apriori(List<Set<String>> transactions, double minSupport, double minConfidence) {
    int n = transactions.size();
    Map<String, Integer> itemCounts = new HashMap<>();
    for (Set<String> t : transactions) { for (String item : t) itemCounts.put(item, itemCounts.getOrDefault(item, 0) + 1); }
    Set<Set<String>> freqSets = new HashSet<>();
    Set<String> L1 = itemCounts.keySet().stream().filter(item -> itemCounts.get(item) / (double) n >= minSupport).collect(Collectors.toSet());
    freqSets.add(L1); int k = 2;
    while (!L1.isEmpty()) {
        int finalK = k;
        List<String> prevList = new ArrayList<>(L1);
        Set<Set<String>> candidates = new HashSet<>();
        for (int i = 0; i < prevList.size(); i++) {
            for (int j = i + 1; j < prevList.size(); j++) {
                Set<String> union = new HashSet<>(); union.add(prevList.get(i)); union.add(prevList.get(j));
                if (union.size() == finalK) candidates.add(union);
            }
        }
        Set<Set<String>> freq = new HashSet<>();
        for (Set<String> cand : candidates) {
            long count = transactions.stream().filter(t -> t.containsAll(cand)).count();
            if (count / (double) n >= minSupport) freq.add(cand);
        }
        freqSets.addAll(freq); L1 = freq.stream().flatMap(Set::stream).collect(Collectors.toSet()); k++;
    }
    return freqSets.stream().flatMap(Set::stream).collect(Collectors.toList());
}

def pagerank(graph, damping=0.85, max_iter=100, tol=1e-6):
    n = len(graph)
    rank = [1.0 / n] * n
    for _ in range(max_iter):
        new_rank = [(1 - damping) / n] * n
        for i in range(n):
            if graph[i]:
                share = rank[i] / len(graph[i])
                for j in graph[i]: new_rank[j] += damping * share
        diff = sum(abs(new_rank[i] - rank[i]) for i in range(n))
        rank = new_rank
        if diff < tol: break
    return rank

function pagerank(graph, damping = 0.85, maxIter = 100, tol = 1e-6) {
    const n = graph.length; let rank = new Array(n).fill(1 / n);
    for (let iter = 0; iter < maxIter; iter++) {
        const newRank = new Array(n).fill((1 - damping) / n);
        for (let i = 0; i < n; i++) {
            if (graph[i].length) { const share = rank[i] / graph[i].length; for (const j of graph[i]) newRank[j] += damping * share; }
        }
        const diff = rank.reduce((s, v, i) => s + Math.abs(v - newRank[i]), 0);
        rank = newRank;
        if (diff < tol) break;
    }
    return rank;
}

public static double[] pagerank(List<List<Integer>> graph, double damping, int maxIter, double tol) {
    int n = graph.size(); double[] rank = new double[n]; Arrays.fill(rank, 1.0 / n);
    for (int iter = 0; iter < maxIter; iter++) {
        double[] newRank = new double[n]; Arrays.fill(newRank, (1 - damping) / n);
        for (int i = 0; i < n; i++) {
            List<Integer> out = graph.get(i);
            if (!out.isEmpty()) { double share = rank[i] / out.size(); for (int j : out) newRank[j] += damping * share; }
        }
        double diff = 0; for (int i = 0; i < n; i++) diff += Math.abs(newRank[i] - rank[i]);
        rank = newRank;
        if (diff < tol) break;
    }
    return rank;
}

func PageRank(graph [][]int, damping float64, maxIter int, tol float64) []float64 {
    n := len(graph); rank := make([]float64, n)
    for i := range rank { rank[i] = 1.0 / float64(n) }
    for iter := 0; iter < maxIter; iter++ {
        newRank := make([]float64, n)
        for i := range newRank { newRank[i] = (1 - damping) / float64(n) }
        for i := 0; i < n; i++ {
            if len(graph[i]) > 0 {
                share := rank[i] / float64(len(graph[i]))
                for _, j := range graph[i] { newRank[j] += damping * share }
            }
        }
        diff := 0.0
        for i := 0; i < n; i++ { diff += math.Abs(newRank[i] - rank[i]) }
        copy(rank, newRank)
        if diff < tol { break }
    }
    return rank
}

function beamSearch(start, goal, expand, beamWidth = 3, maxDepth = 10) {
    let beams = [{ score: 0, path: [start] }];
    for (let d = 0; d < maxDepth; d++) {
        const candidates = [];
        for (const { score, path } of beams) {
            for (const [neighbor, cost] of expand(path[path.length - 1])) {
                const newPath = [...path, neighbor]; const newScore = score + cost;
                if (neighbor === goal) return newPath;
                candidates.push({ score: newScore, path: newPath });
            }
        }
        if (!candidates.length) break;
        candidates.sort((a, b) => a.score - b.score);
        beams = candidates.slice(0, beamWidth);
    }
    return beams.length ? beams.reduce((a, b) => a.score < b.score ? a : b).path : null;
}

func BeamSearch(start, goal string, expand func(string) []struct{ Neighbor string; Cost float64 }, beamWidth int, maxDepth int) []string {
    type beamT struct { score float64; path []string }
    beams := []beamT{{0, []string{start}}}
    for d := 0; d < maxDepth; d++ {
        var candidates []beamT
        for _, b := range beams {
            for _, n := range expand(b.path[len(b.path)-1]) {
                newPath := append([]string{}, b.path...); newPath = append(newPath, n.Neighbor)
                newScore := b.score + n.Cost
                if n.Neighbor == goal { return newPath }
                candidates = append(candidates, beamT{newScore, newPath})
            }
        }
        if len(candidates) == 0 { break }
        sort.Slice(candidates, func(i, j int) bool { return candidates[i].score < candidates[j].score })
        if beamWidth > len(candidates) { beamWidth = len(candidates) }
        beams = candidates[:beamWidth]
    }
    if len(beams) == 0 { return nil }
    best := beams[0]
    for _, b := range beams { if b.score < best.score { best = b } }
    return best.path
}

function exponentialBackoff(attempt, baseDelay = 1000, maxDelay = 60000) {
    const delay = Math.min(baseDelay * Math.pow(2, attempt), maxDelay);
    const jitter = Math.random() * delay * 0.5;
    return new Promise(resolve => setTimeout(resolve, delay + jitter));
}

func ExponentialBackoff(attempt int, baseDelay, maxDelay time.Duration) time.Duration {
    delay := baseDelay * (1 << attempt)
    if delay > maxDelay { delay = maxDelay }
    jitter := time.Duration(rand.Float64() * float64(delay) * 0.5)
    time.Sleep(delay + jitter)
    return delay + jitter
}

function particleSwarm(costFunc, dim, nParticles = 30, maxIter = 100) {
    const particles = Array.from({length: nParticles}, () => ({ pos: Array.from({length: dim}, () => Math.random() * 20 - 10), vel: Array.from({length: dim}, () => Math.random() * 2 - 1), best: null, bestCost: Infinity }));
    let gbest = null, gbestCost = Infinity;
    for (const p of particles) { const cost = costFunc(p.pos); p.best = [...p.pos]; p.bestCost = cost; if (cost < gbestCost) { gbest = [...p.pos]; gbestCost = cost; } }
    const [w, c1, c2] = [0.7, 1.5, 1.5];
    for (let iter = 0; iter < maxIter; iter++) {
        for (const p of particles) {
            for (let d = 0; d < dim; d++) { const r1 = Math.random(), r2 = Math.random(); p.vel[d] = w * p.vel[d] + c1 * r1 * (p.best[d] - p.pos[d]) + c2 * r2 * (gbest[d] - p.pos[d]); p.pos[d] += p.vel[d]; }
            const cost = costFunc(p.pos);
            if (cost < p.bestCost) { p.best = [...p.pos]; p.bestCost = cost; }
            if (cost < gbestCost) { gbest = [...p.pos]; gbestCost = cost; }
        }
    }
    return { gbest, gbestCost };
}

func ParticleSwarm(costFunc func([]float64) float64, dim, nParticles, maxIter int) ([]float64, float64) {
    type particle struct { pos, vel, best []float64; bestCost float64 }
    particles := make([]particle, nParticles); gbest := make([]float64, dim); gbestCost := math.MaxFloat64
    for i := range particles {
        p := &particles[i]; p.pos = make([]float64, dim); p.vel = make([]float64, dim); p.best = make([]float64, dim)
        for d := range p.pos { p.pos[d] = rand.Float64()*20 - 10; p.vel[d] = rand.Float64()*2 - 1 }
        cost := costFunc(p.pos); copy(p.best, p.pos); p.bestCost = cost
        if cost < gbestCost { copy(gbest, p.pos); gbestCost = cost }
    }
    w, c1, c2 := 0.7, 1.5, 1.5
    for iter := 0; iter < maxIter; iter++ {
        for i := range particles {
            p := &particles[i]
            for d := 0; d < dim; d++ {
                r1, r2 := rand.Float64(), rand.Float64()
                p.vel[d] = w*p.vel[d] + c1*r1*(p.best[d]-p.pos[d]) + c2*r2*(gbest[d]-p.pos[d])
                p.pos[d] += p.vel[d]
            }
            cost := costFunc(p.pos)
            if cost < p.bestCost { copy(p.best, p.pos); p.bestCost = cost }
            if cost < gbestCost { copy(gbest, p.pos); gbestCost = cost }
        }
    }
    return gbest, gbestCost
}

import random
def ant_colony(dist_matrix, n_ants=10, n_iter=100, alpha=1, beta=2, evaporation=0.5, q=100):
    n = len(dist_matrix)
    pheromone = [[1.0 / n] * n for _ in range(n)]
    best_path = None; best_cost = float('inf')
    for _ in range(n_iter):
        paths = []
        for _ in range(n_ants):
            visited = [False] * n; path = [0]; visited[0] = True
            for _ in range(n - 1):
                i = path[-1]
                probs = []
                for j in range(n):
                    if not visited[j]:
                        num = (pheromone[i][j] ** alpha) * ((1.0 / dist_matrix[i][j]) ** beta) if dist_matrix[i][j] > 0 else 0
                        den = sum((pheromone[i][k] ** alpha) * ((1.0 / dist_matrix[i][k]) ** beta) for k in range(n) if not visited[k] and dist_matrix[i][k] > 0)
                        probs.append((num / den if den > 0 else 0, j))
                r = random.random(); cum = 0
                for prob, j in probs: cum += prob; if r <= cum: path.append(j); visited[j] = True; break
            paths.append(path)
        for i in range(n):
            for j in range(n): pheromone[i][j] *= (1 - evaporation)
        for path in paths:
            cost = sum(dist_matrix[path[k]][path[k+1]] for k in range(n-1))
            if cost < best_cost: best_path = path; best_cost = cost
            for k in range(n-1): pheromone[path[k]][path[k+1]] += q / cost
    return best_path, best_cost

function antColony(distMatrix, nAnts = 10, nIter = 100, alpha = 1, beta = 2, evaporation = 0.5, q = 100) {
    const n = distMatrix.length;
    let pheromone = Array.from({length: n}, () => new Array(n).fill(1 / n));
    let bestPath = null; let bestCost = Infinity;
    for (let iter = 0; iter < nIter; iter++) {
        const paths = [];
        for (let ant = 0; ant < nAnts; ant++) {
            const visited = new Array(n).fill(false); const path = [0]; visited[0] = true;
            for (let step = 0; step < n - 1; step++) {
                const i = path[path.length - 1];
                const candidates = []; let total = 0;
                for (let j = 0; j < n; j++) {
                    if (!visited[j] && distMatrix[i][j] > 0) { const prob = Math.pow(pheromone[i][j], alpha) * Math.pow(1 / distMatrix[i][j], beta); candidates.push({ prob, j }); total += prob; }
                }
                let r = Math.random() * total;
                for (const c of candidates) { r -= c.prob; if (r <= 0) { path.push(c.j); visited[c.j] = true; break; } }
            }
            paths.push(path);
        }
        for (let i = 0; i < n; i++) for (let j = 0; j < n; j++) pheromone[i][j] *= (1 - evaporation);
        for (const path of paths) {
            let cost = 0; for (let k = 0; k < n - 1; k++) cost += distMatrix[path[k]][path[k+1]];
            if (cost < bestCost) { bestPath = path; bestCost = cost; }
            for (let k = 0; k < n - 1; k++) pheromone[path[k]][path[k+1]] += q / cost;
        }
    }
    return { bestPath, bestCost };
}

public static List<Integer> antColony(double[][] distMatrix, int nAnts, int nIter, double alpha, double beta, double evaporation, double q) {
    int n = distMatrix.length; double[][] pheromone = new double[n][n];
    for (int i = 0; i < n; i++) Arrays.fill(pheromone[i], 1.0 / n);
    List<Integer> bestPath = null; double bestCost = Double.MAX_VALUE; Random rand = new Random();
    for (int iter = 0; iter < nIter; iter++) {
        List<List<Integer>> paths = new ArrayList<>();
        for (int ant = 0; ant < nAnts; ant++) {
            boolean[] visited = new boolean[n]; List<Integer> path = new ArrayList<>(); path.add(0); visited[0] = true;
            for (int step = 0; step < n - 1; step++) {
                int i = path.get(path.size() - 1); double total = 0;
                List<AbstractMap.SimpleEntry<Double, Integer>> candidates = new ArrayList<>();
                for (int j = 0; j < n; j++) { if (!visited[j] && distMatrix[i][j] > 0) { double p = Math.pow(pheromone[i][j], alpha) * Math.pow(1.0 / distMatrix[i][j], beta); candidates.add(new AbstractMap.SimpleEntry<>(p, j)); total += p; } }
                double r = rand.nextDouble() * total;
                for (var c : candidates) { r -= c.getKey(); if (r <= 0) { path.add(c.getValue()); visited[c.getValue()] = true; break; } }
            }
            paths.add(path);
        }
        for (int i = 0; i < n; i++) for (int j = 0; j < n; j++) pheromone[i][j] *= (1 - evaporation);
        for (var path : paths) {
