            if (cost < bestCost) { bestPath = new ArrayList<>(path); bestCost = cost; }
            for (int k = 0; k < n - 1; k++) pheromone[path.get(k)][path.get(k + 1)] += q / cost;
        }
    }
    return bestPath;
}

