def hill_climbing(cost_func, neighbor_func, start, max_iter=1000):
    current = start; current_cost = cost_func(current)
    for _ in range(max_iter):
        neighbor = neighbor_func(current)
        neighbor_cost = cost_func(neighbor)
        if neighbor_cost < current_cost:
            current = neighbor; current_cost = neighbor_cost
        else: break
    return current, current_cost

function hillClimbing(costFunc, neighborFunc, start, maxIter = 1000) {
