class KDTreeNode:
    def __init__(self, point, left=None, right=None):
        self.point = point; self.left = left; self.right = right
class KDTree:
    def __init__(self, points):
        self.k = len(points[0]) if points else 0
        self.root = self._build(points, 0)
    def _build(self, points, depth):
        if not points: return None
        axis = depth % self.k
        points.sort(key=lambda p: p[axis])
        mid = len(points) // 2
        return KDTreeNode(points[mid], self._build(points[:mid], depth+1), self._build(points[mid+1:], depth+1))
    def nearest(self, point, node=None, depth=0, best=None, best_dist=float('inf')):
        if node is None: node = self.root
        if node is None: return best, best_dist
        axis = depth % self.k
        dist = sum((point[i] - node.point[i])**2 for i in range(self.k))
        if dist < best_dist: best, best_dist = node.point, dist
        diff = point[axis] - node.point[axis]
        first, second = (node.left, node.right) if diff <= 0 else (node.right, node.left)
        best, best_dist = self.nearest(point, first, depth+1, best, best_dist)
        if diff**2 < best_dist:
