class KDTree {
    constructor(points) { this.k = points[0] ? points[0].length : 0; this.root = this.build(points, 0); }
    build(points, depth) {
        if (!points.length) return null;
        const axis = depth % this.k;
        points.sort((a, b) => a[axis] - b[axis]);
        const mid = Math.floor(points.length / 2);
        return new KDTreeNode(points[mid], this.build(points.slice(0, mid), depth + 1), this.build(points.slice(mid + 1), depth + 1));
    }
    nearest(point, node = this.root, depth = 0, best = null, bestDist = Infinity) {
        if (!node) return [best, bestDist];
        const axis = depth % this.k;
        const dist = point.reduce((s, v, i) => s + (v - node.point[i]) ** 2, 0);
        if (dist < bestDist) { best = node.point; bestDist = dist; }
        const diff = point[axis] - node.point[axis];
        const [first, second] = diff <= 0 ? [node.left, node.right] : [node.right, node.left];
        [best, bestDist] = this.nearest(point, first, depth + 1, best, bestDist);
        if (diff * diff < bestDist) [best, bestDist] = this.nearest(point, second, depth + 1, best, bestDist);
        return [best, bestDist];
    }
}

public class KDTree {
    private class Node { double[] point; Node left, right; Node(double[] p) { point = p; } }
    private Node root; private int k;
    public KDTree(double[][] points) { k = points[0].length; root = build(points, 0); }
    private Node build(double[][] points, int depth) {
        if (points.length == 0) return null;
        int axis = depth % k;
        Arrays.sort(points, Comparator.comparingDouble(p -> p[axis]));
        int mid = points.length / 2;
        Node node = new Node(points[mid]);
        node.left = build(Arrays.copyOfRange(points, 0, mid), depth + 1);
        node.right = build(Arrays.copyOfRange(points, mid + 1, points.length), depth + 1);
        return node;
    }
    public double[] nearest(double[] point) { return nearest(point, root, 0, null, Double.MAX_VALUE)[0]; }
    private Object[] nearest(double[] point, Node node, int depth, double[] best, double bestDist) {
        if (node == null) return new Object[]{best, bestDist};
        int axis = depth % k;
        double dist = 0; for (int i = 0; i < k; i++) dist += Math.pow(point[i] - node.point[i], 2);
        if (dist < bestDist) { best = node.point; bestDist = dist; }
        double diff = point[axis] - node.point[axis];
        Node first = diff <= 0 ? node.left : node.right;
        Node second = diff <= 0 ? node.right : node.left;
        var r = nearest(point, first, depth + 1, best, bestDist); best = (double[]) r[0]; bestDist = (double) r[1];
        if (diff * diff < bestDist) { r = nearest(point, second, depth + 1, best, bestDist); best = (double[]) r[0]; bestDist = (double) r[1]; }
        return new Object[]{best, bestDist};
    }
}

