        else:
            best = min(range(len(node.entries)), key=lambda i: self._bbox_area(node.entries[i]))
            self.insert(point, node.entries[best])
            node.bbox = self._update_bbox(node)
    def _update_bbox(self, node):
        if not node.entries: return None
        pts = node.entries
        return [min(p[0] for p in pts), min(p[1] for p in pts), max(p[0] for p in pts), max(p[1] for p in pts)]
