        if (node.leaf) { node.entries.push(point); node.bbox = this.updateBBox(node); }
        else { const best = node.entries.reduce((a, b, i) => this.bboxArea(a) <= this.bboxArea(b) ? a : b); this.insert(point, best); node.bbox = this.updateBBox(node); }
    }
    updateBBox(node) { if (!node.entries.length) return null; const pts = node.entries; return [Math.min(...pts.map(p => p[0])), Math.min(...pts.map(p => p[1])), Math.max(...pts.map(p => p[0])), Math.max(...pts.map(p => p[1]))]; }
    bboxArea(node) { const b = node.bbox; return b ? (b[2] - b[0]) * (b[3] - b[1]) : 0; }
}

