func (t *RTree) Insert(point [2]float64, node *RTreeNode) {
    if node == nil { node = t.root }
    if node.leaf { node.entries = append(node.entries, point); t.updateBBox(node); return }
    bestIdx := 0; bestArea := t.bboxArea(node)
    for i := range node.entries { if area := t.bboxArea(&node.entries[i]); area < bestArea { bestIdx = i; bestArea = area } }
