func (t *RTree) updateBBox(node *RTreeNode) {
    if len(node.entries) == 0 { return }
    minX, minY, maxX, maxY := node.entries[0][0], node.entries[0][1], node.entries[0][0], node.entries[0][1]
    for _, p := range node.entries { if p[0] < minX { minX = p[0] }; if p[1] < minY { minY = p[1] }; if p[0] > maxX { maxX = p[0] }; if p[1] > maxY { maxY = p[1] } }
    node.bbox = [4]float64{minX, minY, maxX, maxY}
}
func (t *RTree) bboxArea(node *RTreeNode) float64 { return (node.bbox[2] - node.bbox[0]) * (node.bbox[3] - node.bbox[1]) }

