        pq.sort((a, b) => a[0] - b[0]);
        const [d, node] = pq.shift();
        if (d > dist[node]) continue;
        for (const [neighbor, weight] of graph[node]) { const nd = d + weight; if (nd < dist[neighbor]) { dist[neighbor] = nd; pq.push([nd, neighbor]); } }
    }
    return dist;
}

public static Map<Integer, Integer> dijkstra(Map<Integer, List<int[]>> graph, int start) {
    Map<Integer, Integer> dist = new HashMap<>(); PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> a[1]));
    for (int node : graph.keySet()) dist.put(node, Integer.MAX_VALUE);
    dist.put(start, 0); pq.offer(new int[]{start, 0});
    while (!pq.isEmpty()) {
        int[] cur = pq.poll(); int node = cur[0], d = cur[1];
        if (d > dist.get(node)) continue;
        for (int[] edge : graph.get(node)) { int nd = d + edge[1]; if (nd < dist.get(edge[0])) { dist.put(edge[0], nd); pq.offer(new int[]{edge[0], nd}); } }
    }
    return dist;
}

