import heapq
def prim(graph, start):
    mst = []; visited = {start}; edges = []
    for neighbor, weight in graph[start]: heapq.heappush(edges, (weight, start, neighbor))
    while edges:
        weight, u, v = heapq.heappop(edges)
        if v in visited: continue
        visited.add(v); mst.append((u, v, weight))
        for neighbor, w in graph[v]:
            if neighbor not in visited: heapq.heappush(edges, (w, v, neighbor))
    return mst

function prim(graph, start) {
    const mst = []; const visited = new Set([start]); const edges = [];
    for (const [neighbor, weight] of graph[start]) edges.push([weight, start, neighbor]);
    while (edges.length) {
        edges.sort((a, b) => a[0] - b[0]);
        const [weight, u, v] = edges.shift();
        if (visited.has(v)) continue;
        visited.add(v); mst.push([u, v, weight]);
        for (const [neighbor, w] of graph[v]) { if (!visited.has(neighbor)) edges.push([w, v, neighbor]); }
    }
    return mst;
}

public static List<int[]> prim(List<int[]>[] graph, int start) {
    List<int[]> mst = new ArrayList<>(); Set<Integer> visited = new HashSet<>(); visited.add(start);
    PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> a[0]));
    for (int[] edge : graph[start]) pq.offer(new int[]{edge[1], start, edge[0]});
    while (!pq.isEmpty()) {
        int[] cur = pq.poll(); int weight = cur[0], u = cur[1], v = cur[2];
        if (visited.contains(v)) continue;
        visited.add(v); mst.add(new int[]{u, v, weight});
        for (int[] edge : graph[v]) { if (!visited.contains(edge[0])) pq.offer(new int[]{edge[1], v, edge[0]}); }
    }
    return mst;
}

