def kruskal(edges, n):
    parent = list(range(n))
    def find(x):
        while parent[x] != x: parent[x] = parent[parent[x]]; x = parent[x]
        return x
    def union(x, y): parent[find(x)] = find(y)
    mst = []; edges.sort(key=lambda e: e[2])
    for u, v, w in edges:
        if find(u) != find(v): union(u, v); mst.append((u, v, w))
    return mst

function kruskal(edges, n) {
    const parent = Array.from({length: n}, (_, i) => i);
    function find(x) { while (parent[x] !== x) { parent[x] = parent[parent[x]]; x = parent[x]; } return x; }
    function union(x, y) { parent[find(x)] = find(y); }
    const mst = []; edges.sort((a, b) => a[2] - b[2]);
    for (const [u, v, w] of edges) { if (find(u) !== find(v)) { union(u, v); mst.push([u, v, w]); } }
    return mst;
}

public static List<int[]> kruskal(int[][] edges, int n) {
    int[] parent = new int[n]; for (int i = 0; i < n; i++) parent[i] = i;
    Arrays.sort(edges, Comparator.comparingInt(a -> a[2]));
    List<int[]> mst = new ArrayList<>();
    for (int[] e : edges) { int pu = find(parent, e[0]), pv = find(parent, e[1]); if (pu != pv) { parent[pu] = pv; mst.add(e); } }
    return mst;
}
private static int find(int[] parent, int x) { while (parent[x] != x) { parent[x] = parent[parent[x]]; x = parent[x]; } return x; }

func Kruskal(edges [][3]int, n int) [][3]int {
    parent := make([]int, n); for i := range parent { parent[i] = i }
    var find func(int) int
    find = func(x int) int { if parent[x] != x { parent[x] = find(parent[x]) }; return parent[x] }
    union := func(x, y int) { parent[find(x)] = find(y) }
    sort.Slice(edges, func(i, j int) bool { return edges[i][2] < edges[j][2] })
    var mst [][3]int
    for _, e := range edges { if find(e[0]) != find(e[1]) { union(e[0], e[1]); mst = append(mst, e) } }
    return mst
}

from collections import deque
def topological_sort(graph):
    n = len(graph); in_degree = [0] * n
    for u in range(n):
        for v in graph[u]: in_degree[v] += 1
    q = deque([i for i in range(n) if in_degree[i] == 0])
    result = []
    while q:
        u = q.popleft(); result.append(u)
        for v in graph[u]:
            in_degree[v] -= 1
            if in_degree[v] == 0: q.append(v)
    return result if len(result) == n else None

