        Queue<Integer> q = new LinkedList<>(); q.offer(source); parent[source] = -2;
        while (!q.isEmpty() && parent[sink] == -1) { int u = q.poll(); for (int v = 0; v < n; v++) { if (parent[v] == -1 && residual[u][v] > 0) { parent[v] = u; q.offer(v); } } }
        if (parent[sink] == -1) break;
        int pathFlow = Integer.MAX_VALUE;
        for (int v = sink; v != source; v = parent[v]) { int u = parent[v]; pathFlow = Math.min(pathFlow, residual[u][v]); }
        for (int v = sink; v != source; v = parent[v]) { int u = parent[v]; residual[u][v] -= pathFlow; residual[v][u] += pathFlow; }
