function findMedianSorted(nums1, nums2) {
    const A = nums1.length <= nums2.length ? nums1 : nums2;
    const B = nums1.length <= nums2.length ? nums2 : nums1;
    const m = A.length, n = B.length; let low = 0, high = m;
    while (low <= high) {
        const i = Math.floor((low + high) / 2); const j = Math.floor((m + n + 1) / 2) - i;
        const leftA = i > 0 ? A[i - 1] : -Infinity;
        const rightA = i < m ? A[i] : Infinity;
        const leftB = j > 0 ? B[j - 1] : -Infinity;
        const rightB = j < n ? B[j] : Infinity;
        if (leftA <= rightB && leftB <= rightA) {
            if ((m + n) % 2 === 0) return (Math.max(leftA, leftB) + Math.min(rightA, rightB)) / 2;
            else return Math.max(leftA, leftB);
        } else if (leftA > rightB) high = i - 1;
        else low = i + 1;
    }
    return 0;
}

