        try {
            const parts = token.split('.');
            if (parts.length !== 3) throw new Error();
            const sig = Array.from(new TextEncoder().encode(parts[0] + '.' + parts[1] + secret)).map(b => b.toString(16).padStart(2, '0')).join('');
