import time
def rate_limit_middleware(handler, max_requests=100, window=60):
    requests = {}
    def wrapper(request):
        ip = request.get('ip', 'unknown')
        now = time.time()
        if ip in requests:
            requests[ip] = [t for t in requests[ip] if now - t < window]
            if len(requests[ip]) >= max_requests: return {'error': 'Rate limit exceeded'}, 429
            requests[ip].append(now)
        else: requests[ip] = [now]
        return handler(request)
    return wrapper

