    const requests = {};
    return function(request) {
        const ip = request.ip || 'unknown'; const now = Date.now();
        if (requests[ip]) { requests[ip] = requests[ip].filter(t => now - t < window); if (requests[ip].length >= maxRequests) return { status: 429, body: { error: 'Rate limit exceeded' } }; requests[ip].push(now); }
        else requests[ip] = [now];
        return handler(request);
    };
}

