    type entry struct { times []time.Time; mu sync.Mutex }
    requests := make(map[string]*entry); var mu sync.Mutex
    return func(w http.ResponseWriter, r *http.Request) {
        ip := r.RemoteAddr
        mu.Lock()
        e, ok := requests[ip]
        if !ok { e = &entry{}; requests[ip] = e }
        mu.Unlock()
        e.mu.Lock()
        now := time.Now()
        filtered := make([]time.Time, 0)
        for _, t := range e.times { if now.Sub(t) < window { filtered = append(filtered, t) } }
        e.times = filtered
        if len(e.times) >= maxRequests { e.mu.Unlock(); http.Error(w, `{"error":"Rate limit exceeded"}`, 429); return }
        e.times = append(e.times, now)
        e.mu.Unlock()
        handler(w, r)
    }
}

