class Add extends Expression { constructor(left, right) { super(); this.left = left; this.right = right; } interpret(context) { return this.left.interpret(context) + this.right.interpret(context); } }

type Expression interface{ Interpret(map[string]int) int }
type Number struct{ value int }; func (n Number) Interpret(context map[string]int) int { return n.value }
type Add struct{ left, right Expression }; func (a Add) Interpret(context map[string]int) int { return a.left.Interpret(context) + a.right.Interpret(context) }

class Mediator:
    def notify(self, sender, event): pass
class ConcreteMediator(Mediator):
    def __init__(self, c1, c2): self.c1 = c1; self.c2 = c2; self.c1.mediator = self; self.c2.mediator = self
    def notify(self, sender, event):
        if event == 'A': self.c2.do_c()
        elif event == 'B': self.c1.do_d()
class Component:
    def __init__(self): self.mediator = None
class ComponentA(Component):
    def do_a(self): self.mediator.notify(self, 'A')
    def do_d(self): pass
class ComponentB(Component):
    def do_b(self): self.mediator.notify(self, 'B')
    def do_c(self): pass

class Mediator { notify(sender, event) {} }
class ConcreteMediator extends Mediator { constructor(c1, c2) { super(); this.c1 = c1; this.c2 = c2; c1.mediator = this; c2.mediator = this; } notify(sender, event) { if (event === 'A') this.c2.doC(); if (event === 'B') this.c1.doD(); } }
class Component { constructor() { this.mediator = null; } }
class ComponentA extends Component { doA() { this.mediator.notify(this, 'A'); } doD() {} }
class ComponentB extends Component { doB() { this.mediator.notify(this, 'B'); } doC() {} }

type Mediator interface{ Notify(Component, string) }
type ConcreteMediator struct { c1, c2 Component }; func (m *ConcreteMediator) Notify(sender Component, event string) { if event == "A" { m.c2.(*ComponentB).DoC() }; if event == "B" { m.c1.(*ComponentA).DoD() } }
type Component struct{ mediator Mediator }
type ComponentA struct{ Component }; func (c *ComponentA) DoA() { c.mediator.Notify(c, "A") }; func (c *ComponentA) DoD() {}
type ComponentB struct{ Component }; func (c *ComponentB) DoB() { c.mediator.Notify(c, "B") }; func (c *ComponentB) DoC() {}

class Implementor:
    def operation_impl(self): pass
class ConcreteImplementorA(Implementor):
    def operation_impl(self): return 'A'
class ConcreteImplementorB(Implementor):
    def operation_impl(self): return 'B'
class Abstraction:
    def __init__(self, implementor): self.implementor = implementor
    def operation(self): return f'Abstraction({self.implementor.operation_impl()})'
class RefinedAbstraction(Abstraction):
    def operation(self): return f'Refined({self.implementor.operation_impl()})'

class Implementor { operationImpl() {} }
class ConcreteImplementorA extends Implementor { operationImpl() { return 'A'; } }
class ConcreteImplementorB extends Implementor { operationImpl() { return 'B'; } }
class Abstraction { constructor(implementor) { this.implementor = implementor; } operation() { return `Abstraction(${this.implementor.operationImpl()})`; } }
class RefinedAbstraction extends Abstraction { operation() { return `Refined(${this.implementor.operationImpl()})`; } }

type Implementor interface{ OperationImpl() string }
type ConcreteA struct{}; func (ConcreteA) OperationImpl() string { return "A" }
type ConcreteB struct{}; func (ConcreteB) OperationImpl() string { return "B" }
type Abstraction struct { implementor Implementor }; func (a Abstraction) Operation() string { return "Abstraction(" + a.implementor.OperationImpl() + ")" }
type Refined struct{ Abstraction }; func (r Refined) Operation() string { return "Refined(" + r.implementor.OperationImpl() + ")" }

class Iterator:
    def first(self): pass
    def next(self): pass
    def is_done(self): pass
    def current(self): pass
class ConcreteIterator(Iterator):
    def __init__(self, items): self.items = items; self.index = 0
    def first(self): self.index = 0
    def next(self): self.index += 1
    def is_done(self): return self.index >= len(self.items)
    def current(self): return self.items[self.index] if not self.is_done() else None
class Aggregate:
    def create_iterator(self): pass
class ConcreteAggregate(Aggregate):
    def __init__(self): self.items = []
    def add(self, item): self.items.append(item)
    def create_iterator(self): return ConcreteIterator(self.items)

class Iterator { first() {} next() {} isDone() {} current() {} }
class ConcreteIterator extends Iterator { constructor(items) { super(); this.items = items; this.index = 0; } first() { this.index = 0; } next() { this.index++; } isDone() { return this.index >= this.items.length; } current() { return this.isDone() ? null : this.items[this.index]; } }
class ConcreteAggregate { constructor() { this.items = []; } add(item) { this.items.push(item); } createIterator() { return new ConcreteIterator(this.items); } }

type Iterator interface{ First(); Next(); IsDone() bool; Current() interface{} }
type ConcreteIterator struct { items []interface{}; index int }; func (it *ConcreteIterator) First() { it.index = 0 }; func (it *ConcreteIterator) Next() { it.index++ }; func (it *ConcreteIterator) IsDone() bool { return it.index >= len(it.items) }; func (it *ConcreteIterator) Current() interface{} { if it.IsDone() { return nil }; return it.items[it.index] }
type Aggregate struct { items []interface{} }; func (a *Aggregate) Add(item interface{}) { a.items = append(a.items, item) }; func (a *Aggregate) CreateIterator() Iterator { return &ConcreteIterator{items: a.items} }

import copy
class Prototype:
    def clone(self): return copy.deepcopy(self)
class ConcretePrototype(Prototype):
    def __init__(self, value): self.value = value
